window.MINI_MLS_QUIZ_BANK = {"chapter-08":[{"q":"1. Pearson dùng để đánh giá điều gì?","a":["A. Mối liên hệ tuyến tính giữa hai biến định lượng","B. Độ tin cậy nội tại của thang đo","C. Sự khác biệt trung bình giữa ba nhóm","D. Cấu trúc nhân tố tiềm ẩn"],"correct":0,"explain":"Đáp án A đúng. Pearson đánh giá mối liên hệ tuyến tính."},{"q":"2. Nếu r = 0,611 và p \u003c 0,001 giữa TD và SHL, diễn giải thế nào?","a":["A. TD có tương quan thuận chiều khá mạnh với SHL","B. TD chắc chắn gây ra SHL","C. TD không liên quan đến SHL","D. SHL làm giảm TD"],"correct":0,"explain":"Đáp án A. r dương và p\u003c0,05 chứng tỏ tương quan thuận chiều có ý nghĩa."},{"q":"3. Nếu r = -0,015 và p = 0,822 giữa TT và SHL, kết luận gì?","a":["A. TT chắc chắn không quan trọng","B. Chưa có bằng chứng về tương quan tuyến tính giữa TT và SHL","C. TT gây giảm SHL","D. Phải loại TT khỏi nghiên cứu"],"correct":1,"explain":"Đáp án B. p\u003e=0.05 chưa đủ bằng chứng kết luận tương quan tuyến tính."},{"q":"4. Pearson có chứng minh quan hệ nhân quả không?","a":["A. Có","B. Không","C. Có nếu p \u003c 0,05","D. Có nếu r \u003e 0,5"],"correct":1,"explain":"Đáp án B. Tương quan không phải là nhân quả."},{"q":"5. Trong SPSS, chạy Pearson bằng đường dẫn nào?","a":["A. Analyze → Correlate → Bivariate","B. Analyze → Scale → Reliability Analysis","C. Analyze → Dimension Reduction → Factor","D. Analyze → Regression → Linear"],"correct":0,"explain":"Đáp án A."},{"q":"6. Điều kiện áp dụng Pearson là gì?","a":["A. Hai biến định tính","B. Hai biến định lượng hoặc điểm thang đo tổng hợp","C. Một biến định tính, một định lượng","D. Không cần điều kiện"],"correct":1,"explain":"Đáp án B. Biến định lượng hoặc thang đo tổng hợp (Scale)."},{"q":"7. Hệ số r dao động trong khoảng nào?","a":["A. Từ 0 đến 1","B. Từ 0 đến 100","C. Từ -1 đến +1","D. Từ -âm vô cực đến dương vô cực"],"correct":2,"explain":"Đáp án C. r luôn nằm trong [-1, 1]."},{"q":"8. Hệ số r \u003e 0 mang ý nghĩa gì?","a":["A. Tương quan thuận chiều","B. Tương quan nghịch chiều","C. Không tương quan","D. Sai số chuẩn dương"],"correct":0,"explain":"Đáp án A."},{"q":"9. Hệ số r \u003c 0 mang ý nghĩa gì?","a":["A. Tương quan thuận chiều","B. Tương quan nghịch chiều","C. Lỗi tính toán","D. Quan hệ nhân quả"],"correct":1,"explain":"Đáp án B."},{"q":"10. Hệ số r gần 0 mang ý nghĩa gì?","a":["A. Tương quan rất mạnh","B. Dữ liệu bị lỗi","C. Tương quan tuyến tính yếu hoặc không có tương quan tuyến tính","D. Đa cộng tuyến nghiêm trọng"],"correct":2,"explain":"Đáp án C."},{"q":"11. p-value \u003c 0,05 cho biết điều gì?","a":["A. Tương quan có ý nghĩa thống kê","B. Tương quan mạnh","C. Không có tương quan","D. Cỡ mẫu quá nhỏ"],"correct":0,"explain":"Đáp án A."},{"q":"12. p-value ≥ 0,05 cho biết điều gì?","a":["A. Chắc chắn có tương quan","B. Chưa có bằng chứng đủ mạnh về tương quan tuyến tính","C. Phải xóa biến","D. Hệ số r lớn"],"correct":1,"explain":"Đáp án B."},{"q":"13. Tương quan cao giữa các biến độc lập (vd r \u003e 0,80) cảnh báo điều gì?","a":["A. Mô hình lý tưởng","B. Nguy cơ đa cộng tuyến sơ bộ","C. Sai số ngẫu nhiên","D. Không có vấn đề gì"],"correct":1,"explain":"Đáp án B. Cần theo dõi thêm VIF trong hồi quy."},{"q":"14. Pearson thường được thực hiện sau bước nào?","a":["A. Hồi quy tuyến tính","B. Thống kê mô tả","C. Cronbach\u0027s Alpha và EFA","D. T-test"],"correct":2,"explain":"Đáp án C. Tính biến đại diện sau EFA rồi mới chạy Pearson."},{"q":"15. Biểu đồ nào dùng để kiểm tra mối liên hệ tuyến tính?","a":["A. Pie chart","B. Bar chart","C. Scatterplot","D. Histogram"],"correct":2,"explain":"Đáp án C. Scatterplot (Biểu đồ phân tán)."},{"q":"16. Hàm Excel nào dùng để tính hệ số tương quan?","a":["A. =AVERAGE","B. =CORREL","C. =SUM","D. =VLOOKUP"],"correct":1,"explain":"Đáp án B."},{"q":"17. Two-tailed trong SPSS Pearson có ý nghĩa gì?","a":["A. Kiểm định một phía","B. Kiểm định hai phía","C. Lọc dữ liệu","D. Biểu đồ 2 trục"],"correct":1,"explain":"Đáp án B. Kiểm định hai phía."},{"q":"18. Kết luận chính thức về đa cộng tuyến cần dựa vào chỉ số nào trong hồi quy?","a":["A. p-value","B. Pearson r","C. VIF","D. Cronbach Alpha"],"correct":2,"explain":"Đáp án C."},{"q":"19. Độ lớn 0,30 ≤ |r| \u003c 0,50 được phân loại là gì?","a":["A. Yếu","B. Trung bình","C. Khá mạnh","D. Mạnh"],"correct":1,"explain":"Đáp án B. Trung bình."},{"q":"20. Chức năng nào trong Excel dùng để tạo heatmap tương quan?","a":["A. Data Validation","B. Pivot Table","C. Conditional Formatting → Color Scales","D. VLOOKUP"],"correct":2,"explain":"Đáp án C."}],"chapter-07":[{"q":"Mục đích chính của phân tích EFA sau khi chạy Cronbach\u0027s Alpha là gì?","a":["Kiểm tra xem bệnh nhân có đánh dấu bừa vào bảng hỏi không.","Kiểm tra độ tin cậy (nhất quán) của thang đo.","Kiểm tra giá trị (hội tụ và phân biệt) cấu trúc của thang đo.","Kiểm tra xem biến độc lập có tác động đến biến phụ thuộc không."],"correct":2,"explain":"Cronbach\u0027s Alpha đo lường độ tin cậy. EFA đo lường Giá trị (Validity) để xem các biến có thực sự đo lường đúng cấu trúc lý thuyết (hội tụ/phân biệt) hay không."},{"q":"Chỉ số KMO trong EFA cho biết điều gì và điều kiện đạt là bao nhiêu?","a":["Độ phù hợp của mô hình hồi quy, KMO \u003e 0.05","Sự tương quan giữa các biến, KMO \u003c 0.05","Độ thích hợp của cỡ mẫu để chạy nhân tố, 0.5 ≤ KMO ≤ 1","Phương sai giải thích được, KMO \u003e 50%"],"correct":2,"explain":"KMO (Kaiser-Meyer-Olkin) đo lường sự đầy đủ của cỡ mẫu. Giá trị chuẩn trong nghiên cứu Y dược là từ 0.5 trở lên."},{"q":"Vì sao phải chạy EFA riêng biệt cho nhóm biến Độc lập và nhóm biến Phụ thuộc?","a":["Vì SPSS giới hạn số lượng biến tối đa trong một lần chạy.","Vì biến phụ thuộc và độc lập khác nhau về bản chất lý thuyết, đưa chung sẽ gây nhiễu và tải chéo sai lệch.","Vì biến phụ thuộc luôn có thang đo khác với biến độc lập.","Chỉ là thói quen trình bày, chạy chung hay riêng đều ra kết quả giống nhau."],"correct":1,"explain":"Biến độc lập (nguyên nhân) và biến phụ thuộc (kết quả) là 2 cấu trúc khái niệm hoàn toàn tách biệt. Đưa chung vào EFA sẽ phá vỡ giá trị phân biệt của nghiên cứu."},{"q":"Giá trị Eigenvalue ≥ 1 mang ý nghĩa gì trong bảng kết quả EFA?","a":["Mức độ tin cậy của nhân tố đó lớn hơn 100%.","Nhân tố được giữ lại giải thích được nhiều thông tin hơn một biến quan sát đơn lẻ.","Tương quan giữa nhân tố và biến phụ thuộc là thuận chiều.","Cỡ mẫu đã vượt quá 100 người."],"correct":1,"explain":"Eigenvalue đại diện cho phần phương sai mà nhân tố giải thích. Một biến đơn lẻ có phương sai chuẩn hóa = 1. Do đó nhân tố phải có Eigenvalue ≥ 1 mới có giá trị giữ lại."},{"q":"Tổng phương sai trích (Total Variance Explained) trong luận văn CK1 thường được yêu cầu đạt tối thiểu bao nhiêu?","a":["30%","50%","75%","95%"],"correct":1,"explain":"Trong nhóm ngành khoa học xã hội và y dược cộng đồng, tổng phương sai trích ≥ 50% được coi là đạt yêu cầu thực tiễn."},{"q":"Tại mục Options của EFA trong SPSS, tại sao chúng ta nên nhập giá trị \u00270.50\u0027 vào ô \u0027Suppress small coefficients\u0027?","a":["Để xóa luôn các biến có giá trị nhỏ hơn 0.5 khỏi bộ dữ liệu.","Để hệ thống tự động làm tròn các số lên 0.5.","Để ẩn đi các hệ số tải (Factor Loading) \u003c 0.5, giúp bảng Rotated Matrix gọn gàng, dễ nhìn giá trị hội tụ hơn.","Để bắt SPSS ép các biến phải có hệ số lớn hơn 0.5."],"correct":2,"explain":"Lệnh Suppress chỉ có tác dụng \u0027ẩn\u0027 (không hiển thị) các con số nhỏ để mắt người đọc dễ dàng nhìn ra các cột hội tụ, nó không xóa biến hay làm tròn dữ liệu gốc."},{"q":"Trong bảng Rotated Component Matrix, câu hỏi HQ1 có hệ số tải (Factor loading) ở nhân tố 1 là 0.752, ở nhân tố 2 là 0.680. Anh/chị quyết định thế nào?","a":["Giữ lại vì 0.752 \u003e 0.5.","Loại bỏ câu HQ1 vì xảy ra hiện tượng Tải chéo (Cross-loading) với mức chênh lệch Δ \u003c 0.3.","Tính trung bình cộng 2 hệ số này.","Kéo câu HQ1 sang nhóm của nhân tố 2."],"correct":1,"explain":"Δ = |0.752 - 0.680| = 0.072 (nhỏ hơn rất nhiều so với 0.3). Bệnh nhân đang hiểu nhầm câu hỏi này sang cả 2 khía cạnh. Cần loại bỏ để đảm bảo Giá trị phân biệt."},{"q":"Khi chạy EFA cho 3 câu hỏi Sự hài lòng (SHL1, SHL2, SHL3), SPSS báo \u0027Only one component was extracted. The solution cannot be rotated.\u0027 Anh chị sẽ giải thích thế nào trong luận văn?","a":["Thang đo bị lỗi, cần thiết kế lại bảng hỏi.","Dữ liệu có nhiều Outlier (ngoại lệ), cần làm sạch lại.","Đây là kết quả tốt, chứng tỏ 3 câu hội tụ hoàn toàn thành 1 nhân tố duy nhất, không cần xoay ma trận.","SPSS bị lỗi bản quyền (Lỗi 1099), cần cài đặt lại."],"correct":2,"explain":"Khi các biến thực sự đo lường cùng một khái niệm duy nhất, phần mềm chỉ rút ra 1 nhân tố, do đó về mặt toán học không cần (và không thể) xoay trục (Rotate)."},{"q":"Để sử dụng kết quả EFA cho bước Hồi quy tuyến tính phía sau, chúng ta phải dùng chức năng gì trong SPSS?","a":["Analyze \u003e Descriptive Statistics","Transform \u003e Compute Variable (tính điểm trung bình nhân tố)","Transform \u003e Recode into Same Variables","Data \u003e Select Cases"],"correct":1,"explain":"Sau khi EFA khẳng định các biến hội tụ tốt, ta dùng Compute Variable để tính trung bình (Ví dụ: MEAN(HQ1, HQ2, HQ3)) tạo thành biến đại diện để chạy Hồi quy."},{"q":"Một nguyên tắc \u0027sống còn\u0027 khi loại bỏ biến quan sát do Factor Loading \u003c 0.5 trong nghiên cứu y dược lâm sàng là gì?","a":["Luôn luôn xóa ngay lập tức không cần suy nghĩ.","Chỉ xóa nếu p-value \u003e 0.05.","Không được xóa cơ học; phải xem xét ý nghĩa lâm sàng của biến đó, có thể giữ lại nếu thầy cô hướng dẫn đồng ý vì lý do chuyên môn.","Nhân đôi giá trị của biến đó trong Excel rồi import lại SPSS."],"correct":2,"explain":"Thống kê chỉ là công cụ hỗ trợ. Ý nghĩa thực tiễn lâm sàng luôn phải được đặt lên hàng đầu. Không bỏ biến cơ học chỉ vì một chỉ số hơi thiếu một chút."},{"q":"Phép xoay Varimax trong EFA thuộc loại phép xoay nào?","a":["Xoay xiên (Oblique), giả định các nhân tố có tương quan.","Xoay vuông góc (Orthogonal), giả định các nhân tố độc lập (không tương quan).","Xoay đồng tâm.","Xoay ngẫu nhiên."],"correct":1,"explain":"Varimax là phép xoay vuông góc (Orthogonal), nó tối đa hóa sự phân tán của hệ số tải, giúp phân định rõ ràng ranh giới giữa các nhân tố độc lập với nhau."},{"q":"Khi đọc kiểm định Bartlett\u0027s Test of Sphericity, giả thuyết Ho (Null hypothesis) của kiểm định này là gì?","a":["Các biến quan sát không có tương quan với nhau trong tổng thể (Ma trận tương quan là ma trận đơn vị).","Các biến quan sát có tương quan hoàn hảo.","Cỡ mẫu phân phối chuẩn.","Phương sai của các biến là đồng nhất."],"correct":0,"explain":"Bartlett\u0027s Test kiểm tra giả thuyết Ho: \u0027Ma trận tương quan là ma trận đơn vị\u0027 (các biến rời rạc, không liên quan). Ta mong muốn bác bỏ Ho (Sig \u003c 0.05) để chứng tỏ các biến có tương quan, đủ điều kiện gom nhóm."},{"q":"Nếu hệ số KMO trong output EFA của anh/chị là 0.450. Hành động đúng nhất là:","a":["Tiếp tục chạy hồi quy vì KMO không quan trọng.","Kết luận mô hình hồi quy không phù hợp.","Tìm cách tăng cỡ mẫu, hoặc loại bỏ các biến có tương quan quá yếu với phần còn lại để xem KMO có cải thiện không.","Thay đổi phương pháp xoay sang Promax."],"correct":2,"explain":"KMO \u003c 0.5 báo hiệu cỡ mẫu hoặc sự tương quan trong tập dữ liệu không đủ tốt để phân tích nhân tố. Tăng cỡ mẫu hoặc loại biến nhiễu là giải pháp."},{"q":"Trong bảng Communalities (Phương sai trích của từng biến), chỉ số Extraction biểu thị điều gì?","a":["Tỷ lệ % bệnh nhân trả lời câu hỏi đó.","Phần trăm phương sai của biến đó được giải thích bởi các nhân tố đã trích xuất.","Số lỗi nhập liệu của biến đó.","Hệ số tin cậy của biến đó."],"correct":1,"explain":"Communalities (Extraction) cho biết các nhân tố chung giải thích được bao nhiêu % sự biến thiên của chính biến quan sát đó. Càng gần 1 càng tốt."},{"q":"Câu hỏi \u0027Chi phí điều trị hợp lý\u0027 (CP1) nằm trong nhóm biến phụ thuộc hay độc lập đối với mô hình đánh giá Sự hài lòng (SHL)?","a":["Biến phụ thuộc, vì chi phí phụ thuộc vào bệnh viện.","Biến độc lập (yếu tố tác động/dự báo sự hài lòng).","Biến nền.","Biến nhiễu."],"correct":1,"explain":"Trong mô hình này, Chi phí (CP) là một trong những nguyên nhân (Độc lập) dẫn đến kết quả là Sự hài lòng (Phụ thuộc)."},{"q":"Anh chị chạy EFA lần 1, biến TD3 bị tải chéo (Cross-loading) với $\\\\Delta = 0.1$. Bước tiếp theo trên SPSS là:","a":["Để nguyên và copy kết quả vào Word.","Sửa số liệu trong SPSS Data View cho đến khi không bị tải chéo.","Quay lại hộp thoại EFA, bỏ biến TD3 ra khỏi ô Variables, chạy lại lần 2.","Xóa toàn bộ nhóm biến Thái độ (TD)."],"correct":2,"explain":"Quy trình chuẩn khi gặp tải chéo vi phạm là: Loại biến vi phạm khỏi mô hình EFA hiện tại và thực hiện chạy lại EFA cho các biến còn lại."},{"q":"Sự khác biệt lớn nhất về mặt hình thức trình bày Bảng EFA trong luận văn so với xuất trực tiếp từ SPSS là gì?","a":["Chỉ việc copy paste, không có gì khác biệt.","Phải tự đánh lại bảng, đổi dấu phẩy thập phân theo chuẩn tiếng Việt, gom các biến thành nhóm hội tụ rõ ràng để hội đồng dễ nhìn.","Phải dịch toàn bộ sang tiếng Anh.","Đổi màu bảng thành màu xanh y tế."],"correct":1,"explain":"Output của SPSS (Rotated Matrix) hiển thị rất thô. Trong luận văn học thuật, phải thiết kế lại bảng (như Module 5), định dạng số liệu, loại bỏ giá trị rỗng để làm nổi bật tính hội tụ."},{"q":"Khi một biến \u0027bay\u0027 (tách) ra đứng một mình thành một nhân tố mới (chỉ có duy nhất 1 câu hỏi trong nhân tố đó), theo lý thuyết y sinh học, ta nên làm gì?","a":["Đổi tên nhân tố đó cho thật hay và giữ lại phân tích Hồi quy.","Xem xét loại bỏ, vì một khái niệm lý thuyết thường cần ít nhất 3 (hoặc 2) biến quan sát để đo lường độ tin cậy.","Ép nó vào nhân tố kế bên bằng Excel.","Nhân bản biến đó lên làm 3 lần."],"correct":1,"explain":"Một nhân tố chỉ có 1 biến đo lường thì không thể đánh giá độ tin cậy nội tại và thường không đại diện đủ sâu cho một cấu trúc khái niệm. Thường xem xét loại bỏ."},{"q":"Phân tích nhân tố khám phá (EFA) khác biệt với Phân tích nhân tố khẳng định (CFA) ở điểm nào cơ bản nhất?","a":["EFA dùng cho biến liên tục, CFA dùng cho biến định tính.","EFA tìm kiếm số lượng nhân tố tự do từ dữ liệu, CFA yêu cầu khai báo cấu trúc nhân tố từ trước để kiểm định.","EFA dùng SPSS, CFA tuyệt đối không thể dùng phần mềm máy tính.","Không có sự khác biệt."],"correct":1,"explain":"EFA (Exploratory - Khám phá) để dữ liệu tự nhóm lại. CFA (Confirmatory - Khẳng định, thường chạy trên AMOS/SmartPLS) yêu cầu nhà nghiên cứu chỉ định biến nào thuộc nhân tố nào trước khi chạy để kiểm tra độ phù hợp."},{"q":"Bạn chuẩn bị báo cáo luận văn, thầy phản biện hỏi: \u0027Tại sao anh không đưa Sự Hài Lòng (SHL) vào chạy EFA cùng với nhóm Thái độ, Chi phí, Hiệu quả?\u0027. Bạn trả lời dựa trên chuyên môn phương pháp luận:","a":["Dạ vì SPSS máy em bị lỗi 1099 ạ.","Dạ em quên mất ạ.","Dạ, vì theo nguyên tắc đo lường, nhóm biến độc lập và biến phụ thuộc có bản chất khái niệm khác nhau. Đưa chung vào EFA sẽ phá vỡ cấu trúc mô hình gốc và gây nhiễu, tải chéo vô lý ạ.","Dạ vì sách thầy viết thế nên em làm theo."],"correct":2,"explain":"Đây là câu hỏi kinh điển bảo vệ luận văn. Phải nắm vững lý do là bảo vệ \u0027Cấu trúc lý thuyết\u0027 của mô hình (Độc lập phân biệt với Phụ thuộc)."}],"chapter-05":[{"q":"Học viên đang tiến hành thống kê mô tả biến Giới tính (mã hóa 1.0 = Nam, 2.0 = Nữ). Chỉ số nào sau đây TUYỆT ĐỐI không được phép sử dụng?","a":["A. Tần số (N)","B. Trị số trung bình (Mean)","C. Tỷ lệ phần trăm (Valid Percent)","D. Tỷ lệ phần trăm thực tế (Percent)"],"correct":1,"explain":"Giới tính là biến định danh (Nominal). Việc tính trung bình cộng của mã hóa 1 và 2 là hoàn toàn vô nghĩa về mặt logic y khoa."},{"q":"Sự khác biệt căn bản giữa hai chỉ số Percent và Valid Percent trong bảng kết quả thống kê tần số (Frequencies) của SPSS là gì?","a":["A. Valid Percent luôn lớn hơn Percent trong mọi trường hợp.","B. Valid Percent tự động loại trừ các trường hợp khuyết thiếu (Missing data), trong khi Percent tính trên toàn bộ cỡ mẫu.","C. Percent loại trừ missing, Valid Percent giữ lại.","D. Hai chỉ số này luôn luôn bằng nhau."],"correct":1,"explain":"Valid Percent chỉ tính trên số mẫu thực tế có nhập liệu câu trả lời (loại bỏ Missing), giúp báo cáo tỷ lệ cấu cấu chính xác hơn."},{"q":"Khi mô tả một biến định lượng có phân phối chuẩn (ví dụ: Tuổi bệnh nhân), bộ đôi chỉ số nào bắt buộc phải báo cáo đi kèm nhau?","a":["A. Mean và Median","B. Mean và Standard Deviation (SD)","C. Median và Khoảng tứ phân vị (IQR)","D. Mode và Range"],"correct":1,"explain":"Đối với phân phối chuẩn, trị số Trung bình (Mean) và Độ lệch chuẩn (SD) là bộ đôi chuẩn mực để mô tả xu hướng trung tâm và mức độ phân tán."},{"q":"Nếu dữ liệu biến định lượng bị lệch nặng hoặc có chứa các điểm dị biệt cực lớn (Outliers), chỉ số nào tốt nhất đại diện cho xu hướng trung tâm thay thế cho Mean?","a":["A. Mode","B. Standard Deviation (SD)","C. Median (Trung vị)","D. Range"],"correct":2,"explain":"Median (trung vị) chia đôi mẫu số liệu nên không bị ảnh hưởng bởi các giá trị cực trị lệch nặng."},{"q":"Để đánh giá nhanh sự phân phối của một biến định lượng liên tục có tuân theo quy luật phân phối chuẩn hay không, loại biểu đồ nào thích hợp nhất?","a":["A. Pie chart (Biểu đồ quạt)","B. Bar chart (Biểu đồ cột)","C. Histogram (Biểu đồ tần suất dạng cột liền kề)","D. Line chart"],"correct":2,"explain":"Histogram giúp quan sát dạng hình chuông úp của dữ liệu để đánh giá sơ bộ giả định phân phối chuẩn."},{"q":"Trong khảo sát mức độ hài lòng theo Likert 5 điểm, khoảng cách (Interval) để phân chia 5 cấp độ từ \u0027Rất thấp\u0027 đến \u0027Rất cao\u0027 được tính theo công thức nào?","a":["A. (5 - 1) / 5 = 0.80","B. (5 - 1) / 4 = 1.00","C. (5 - 0) / 5 = 1.00","D. (5 - 1) / 3 = 1.33"],"correct":0,"explain":"Công thức chuẩn là (Max - Min) / n = (5 - 1) / 5 = 0.80, tương ứng với các khoảng rộng đều nhau là 0.80."},{"q":"Nhân tố Thái độ phục vụ (TD) có điểm trung bình Mean = 3.95 và SD = 0.58. Dựa trên khoảng chia 0.80, nhân tố này được xếp vào cấp độ nào?","a":["A. Trung bình","B. Cao","C. Rất cao","D. Thấp"],"correct":1,"explain":"Khoảng đánh giá \u0027Cao\u0027 nằm từ 3.41 đến 4.20. Giá trị 3.95 thuộc khoảng này."},{"q":"Bảng chéo kết hợp (Crosstabs) trong SPSS có chức năng chính là gì?","a":["A. Tính toán điểm trung bình của các biến độc lập.","B. Biểu diễn mối liên hệ phân bố tần số và tỷ lệ giữa hai hoặc nhiều biến định tính.","C. Kiểm định xem hai biến định lượng có tương quan với nhau không.","D. Tìm ra phương trình hồi quy tuyến tính."],"correct":1,"explain":"Crosstabs chuyên dùng để biểu diễn tương tác tần số chéo giữa các biến phân loại."},{"q":"Khi phân tích bảng Crosstabs so sánh sự hài lòng giữa Nam và Nữ, bạn thấy tỷ lệ hài lòng ở Nữ là 85.7% và Nam là 72.2%. Kết luận nào sau đây là khoa học nhất?","a":["A. Chắc chắn Nữ hài lòng nhiều hơn Nam có ý nghĩa thống kê.","B. Tỷ lệ hài lòng ở Nữ có xu hướng cao hơn Nam trong mẫu khảo sát; cần thực hiện thêm phép kiểm Chi-Square để kết luận sự khác biệt này có ý nghĩa thống kê hay không.","C. Không có sự khác biệt nào giữa hai nhóm.","D. Nam hài lòng nhiều hơn Nữ."],"correct":1,"explain":"Bảng chéo chỉ mô tả phân bố mẫu, chưa thể tự động kết luận ý nghĩa thống kê của sự khác biệt nếu chưa qua phép kiểm suy luận."},{"q":"Hàm nào trong Excel giúp bạn đếm số lượng bệnh nhân thỏa mãn đồng thời hai điều kiện: Giới tính là Nữ (mã là 2) và Hài lòng (mã là 1)?","a":["A. COUNTIF","B. COUNTIFS","C. SUMIF","D. VLOOKUP"],"correct":1,"explain":"COUNTIFS cho phép đếm tần số thỏa mãn nhiều điều kiện đồng thời trong Excel."},{"q":"Để nhận diện nhanh các giá trị ngoại lệ cực đoan (Outliers) có thể do lỗi nhập liệu thô gây ra, biểu đồ trực quan nào sau đây là tối ưu nhất?","a":["A. Histogram","B. Boxplot (Biểu đồ hộp râu)","C. Pie chart","D. Scatter plot"],"correct":1,"explain":"Boxplot biểu diễn rõ các điểm dị biệt (vượt ngoài hàng rào trên/dưới) bằng các ký hiệu vòng tròn hoặc dấu sao."},{"q":"Học viên muốn so sánh tỷ lệ hài lòng của bệnh nhân theo 5 nhóm trình độ học vấn. Biểu đồ nào trực quan nhất để biểu diễn tỷ lệ này?","a":["A. Biểu đồ quạt (Pie chart)","B. Biểu đồ cột chồng hoặc nhóm (Grouped/Stacked Bar Chart)","C. Biểu đồ đường thẳng (Line Chart)","D. Biểu đồ Histogram"],"correct":1,"explain":"Grouped/Stacked Bar Chart giúp hiển thị và so sánh cấu trúc phần trăm một cách rõ nét qua nhiều phân nhóm trình độ học vấn."},{"q":"Trước khi thực hiện phân tích thống kê suy luận (như kiểm định T-test hay phân tích hồi quy), bước nào sau đây là BẮT BUỘC?","a":["A. Viết phần thảo luận.","B. Chạy thống kê mô tả để kiểm tra phân phối, tính chất biến và làm sạch dữ liệu.","C. Vẽ biểu đồ 3D phức tạp.","D. Loại bỏ cơ học 50% cỡ mẫu."],"correct":1,"explain":"Thống kê mô tả là nền tảng bắt buộc để định hướng, rà soát lỗi nhập liệu và kiểm tra các giả định thống kê."},{"q":"Trong phần mềm SPSS, đường dẫn lệnh nào dùng để xuất nhanh bảng chéo Crosstabs có kèm tính phần trăm theo dòng?","a":["A. Analyze -\u003e Descriptives -\u003e Frequencies","B. Analyze -\u003e Descriptive Statistics -\u003e Crosstabs -\u003e Cells (chọn Row %)","C. Analyze -\u003e Compare Means -\u003e One-Way ANOVA","D. Graphs -\u003e Chart Builder"],"correct":1,"explain":"Đây là đường dẫn chuẩn xác để thực hiện bảng chéo và khai báo tùy chọn tỷ lệ % theo dòng."},{"q":"Lợi ích lớn nhất của việc thiết lập Data Validation (giới hạn nhập liệu từ 1 đến 5) trên file Excel trước khi đưa vào SPSS là gì?","a":["A. Giúp SPSS chạy nhanh hơn.","B. Ngăn chặn triệt để lỗi nhập liệu vượt quá phạm vi (nhập nhầm số 6, 33...) tránh biến dạng điểm trung bình.","C. Tự động mã hóa biến.","D. Loại bỏ dữ liệu missing."],"correct":1,"explain":"Data Validation hoạt động như một màng lọc ngăn chặn các giá trị vô lý nhập sai ngay từ nguồn Excel."},{"q":"Trong báo cáo luận văn, điểm số trung bình của một thang đo Likert được báo cáo là 3.88. Con số này phản ánh điều gì?","a":["A. Bệnh nhân hoàn toàn không đồng ý.","B. Mức độ đồng ý/hài lòng chung nằm ở ngưỡng Khá (Cao).","C. Dữ liệu bị lỗi nghiêm trọng.","D. Phân phối mẫu bị lệch trái hoàn toàn."],"correct":1,"explain":"3.88 thuộc khoảng từ 3.41 đến 4.20, là mức độ đánh giá cao (Khá) trên thang đo sự hài lòng."},{"q":"Nếu thang đo Chi Phí (CP) có điểm trung bình rất thấp (Mean = 2.84), nhà quản lý bệnh viện nên tập trung hành động gì?","a":["A. Tăng giá thuốc lên cao hơn.","B. Cải thiện tính minh bạch, công khai chi phí điều trị và tư vấn rõ ràng khả năng chi trả cho người bệnh.","C. Giảm chất lượng dịch vụ điều trị xuống.","D. Bỏ qua không cần xử lý."],"correct":1,"explain":"Ý nghĩa thực tiễn: Điểm CP thấp đồng nghĩa cảm nhận về tính minh bạch và hợp lý chi phí kém, đòi hỏi giải pháp quản lý công khai minh bạch hơn."},{"q":"Công thức toán học của trị số Trung vị (Median) dựa trên nguyên lý nào sau đây?","a":["A. Cộng tất cả các giá trị rồi chia cho cỡ mẫu.","B. Là giá trị đứng ở vị trí chính giữa khi chuỗi số liệu đã được sắp xếp tăng dần.","C. Là giá trị có tần số xuất hiện cao nhất.","D. Là bình phương của độ lệch chuẩn."],"correct":1,"explain":"Trung vị là giá trị định vị chia đôi tập dữ liệu thành hai phần có số lượng quan sát bằng nhau."},{"q":"Tại sao trong nghiên cứu khoa học y học, biểu đồ hình quạt (Pie chart) không nên dùng cho biến có quá nhiều nhóm phân loại?","a":["A. Do phần mềm SPSS sẽ báo lỗi hệ thống.","B. Do các lát cắt quạt quá nhỏ và chồng chéo nhãn, làm người đọc không thể phân biệt và tiếp thu thông tin.","C. Do Pie chart không tính được phần trăm.","D. Do Pie chart chỉ dùng được cho biến định lượng."],"correct":1,"explain":"Sự phân mảnh quá mức trong biểu đồ Pie Chart làm mất đi tính trực quan vốn có của biểu đồ."},{"q":"Một học viên viết trong luận văn: \u0027Do phần mềm SPSS tính toán ra thời gian điều trị trung bình là 10.5 ngày nên chúng tôi khẳng định phác đồ điều trị này là tối ưu nhất\u0027. Nhận xét này vi phạm nguyên tắc nào?","a":["A. Vi phạm quy tắc làm tròn số.","B. Quá phụ thuộc vào công cụ tính toán mà bỏ quên tư duy phản biện chuyên môn y học (SPSS chỉ hỗ trợ tính toán, không quyết định thay tư duy biện giải kết quả).","C. Sử dụng sai thuật ngữ thống kê.","D. Chạy sai thuật toán mô tả."],"correct":1,"explain":"Excel hay SPSS chỉ là công cụ hỗ trợ tính toán số liệu. Việc biện giải ý nghĩa thực tế và tính tối ưu đòi hỏi kiến thức chuyên môn sâu sắc của người làm nghiên cứu."}],"chapter-10":[{"q":"Khi so sánh điểm hài lòng chung SHL giữa bệnh nhân nam và nữ trong mẫu nghiên cứu, dược sĩ chuyên khoa nên chọn phép kiểm nào?","a":["Independent Samples T-test","One-way ANOVA","Paired-Samples T-test","Chi-Square Test"],"correct":0,"explain":"GioiTinh chỉ có đúng 2 nhóm độc lập (Nam và Nữ). Phép so sánh trung bình 2 nhóm độc lập chuẩn là Independent Samples T-test."},{"q":"Khi so sánh điểm SHL giữa 4 nhóm khả năng chi trả điều trị khác nhau, phép kiểm cơ bản nào được áp dụng?","a":["Independent Samples T-test","One-way ANOVA","Tương quan Pearson","Hồi quy tuyến tính"],"correct":1,"explain":"Khi so sánh trung bình định lượng của từ 3 nhóm trở lên (KhaNangChiTra có 4 nhóm), ta sử dụng One-way ANOVA."},{"q":"Kiểm định sự đồng nhất phương sai của Levene\u0027s Test đóng vai trò gì trước khi đọc t-test hoặc ANOVA?","a":["Kiểm định mức độ tin cậy của thang đo","Kiểm tra giả định phân phối chuẩn","Kiểm tra giả định đồng nhất phương sai giữa các nhóm so sánh","Kiểm tra hiện tượng đa cộng tuyến"],"correct":2,"explain":"Levene\u0027s Test dùng để kiểm tra xem phương sai của biến phụ thuộc có bằng nhau (đồng nhất) giữa các nhóm so sánh hay không."},{"q":"Nếu kiểm định Levene trong phép kiểm Independent Samples T-test có p = 0,963, ta nên đọc dòng nào trong kết quả SPSS?","a":["Dòng \u0027Equal variances assumed\u0027","Dòng \u0027Equal variances not assumed\u0027","Bảng Robust Tests (Welch)","Không đọc dòng nào vì kết quả bị lỗi"],"correct":0,"explain":"Vì p = 0,963 ≥ 0,05, phương sai đồng nhất được chấp nhận. Ta đọc dòng đầu tiên: Equal variances assumed."},{"q":"Trong Independent T-test, nếu Levene có p = 0,020 (nhỏ hơn 0,05), dòng kết quả t-test nào cần được báo cáo?","a":["Dòng \u0027Equal variances assumed\u0027","Dòng \u0027Equal variances not assumed\u0027","Đọc bảng ANOVA thay thế","Phải xóa bớt mẫu nghiên cứu"],"correct":1,"explain":"Khi Levene có p \u003c 0,05, phương sai không đồng nhất. Ta phải đọc dòng thứ hai đã được hiệu chỉnh: Equal variances not assumed."},{"q":"Khi chạy One-way ANOVA so sánh SHL theo lứa tuổi (4 nhóm), Levene p = 0,025. Dược sĩ cần ưu tiên đọc chỉ số nào?","a":["ANOVA thường (hàng Between Groups)","Welch ANOVA ( Robust Tests of Equality of Means)","Independent Samples T-test","Tương quan Pearson"],"correct":1,"explain":"Khi ANOVA bị vi phạm giả định đồng nhất phương sai (p = 0,025 \u003c 0,05), bảng kiểm định điều chỉnh Welch ANOVA có độ tin cậy vượt trội hơn."},{"q":"Trong nghiên cứu cắt ngang về sự hài lòng, kiểm định t-test cho thấy khác biệt hài lòng giữa nam và nữ có p = 0,482. Kết luận nào phù hợp?","a":["Giới tính nữ quyết định mức độ hài lòng cao hơn","Nam giới hài lòng kém hơn nữ giới có ý nghĩa","Chưa có bằng chứng về sự khác biệt có ý nghĩa thống kê về SHL giữa nam và nữ","Giới tính nam là nguyên nhân gây giảm hài lòng"],"correct":2,"explain":"p = 0,482 \u003e 0,05, do đó không có sự khác biệt có ý nghĩa thống kê. Ta dùng từ \u0027Chưa có bằng chứng\u0027."},{"q":"ANOVA so sánh SHL theo 4 mức độ phác đồ có F = 1,759 và p = 0,156. Nhận xét nào chuẩn mực nhất cho báo cáo?","a":["Phác đồ 2 làm tăng sự hài lòng có ý nghĩa thống kê","Chưa tìm thấy sự khác biệt có ý nghĩa thống kê về điểm hài lòng chung SHL theo phác đồ điều trị","Phác đồ điều trị không có tác dụng lâm sàng nào","Cần chạy Post-hoc ngay lập tức"],"correct":1,"explain":"p = 0,156 \u003e 0,05 cho thấy ANOVA tổng thể không đạt ý nghĩa thống kê ở mức 5%."},{"q":"Tại sao không nên kết luận \u0027Sự thay đổi phác đồ quyết định sự hài lòng\u0027 chỉ dựa trên phép kiểm ANOVA có ý nghĩa thống kê (p \u003c 0,05) trong nghiên cứu cắt ngang?","a":["Vì ANOVA có sai số quá lớn","Vì nghiên cứu cắt ngang không chứng minh được trình tự thời gian nguyên nhân - kết quả","Vì SPSS không chạy được phân tích nhân quả","Vì phác đồ điều trị không có giá trị lâm sàng"],"correct":1,"explain":"Thiết kế cắt ngang thu thập dữ liệu tại cùng một thời điểm, chỉ cho thấy mối liên quan hiện hữu, không đủ logic chứng minh quan hệ nhân quả."},{"q":"Khi ANOVA có ý nghĩa tổng thể (F = 9,929; p \u003c 0,001) với biến tài chính gồm 4 nhóm, thao tác thống kê bắt buộc tiếp theo là gì?","a":["Chạy Cronbach\u0027s Alpha lại","Thực hiện phép so sánh cặp Post-hoc","Chạy hồi quy tuyến tính","Làm sạch lại toàn bộ dữ liệu"],"correct":1,"explain":"ANOVA tổng thể có ý nghĩa chỉ khẳng định có ít nhất một cặp nhóm khác nhau. Muốn biết chính xác nhóm nào khác nhóm nào, bắt buộc phải chạy Post-hoc."},{"q":"Nếu phương sai giữa các nhóm học vấn đồng nhất (Levene p = 0,707), phép kiểm Post-hoc nào thích hợp nhất để báo cáo?","a":["Tamhane\u0027s T2","Bonferroni","Games-Howell","Dunnett\u0027s T3"],"correct":1,"explain":"Khi phương sai đồng nhất, phép kiểm Post-hoc kiểm soát tốt sai số loại I là Bonferroni hoặc Tukey."},{"q":"Nếu kiểm định Welch ANOVA có ý nghĩa (p \u003c 0,001) nhưng kiểm định Levene bị vi phạm (p = 0,002), phép kiểm Post-hoc nào được y văn ưu tiên?","a":["Bonferroni","Tamhane\u0027s T2","Tukey","LSD"],"correct":1,"explain":"Khi phương sai không đồng nhất (vi phạm giả định), ta bắt buộc phải sử dụng phép so sánh cặp hiệu chỉnh như Tamhane\u0027s T2."},{"q":"Một so sánh cặp Post-hoc Bonferroni giữa nhóm \u0027Rất khó khăn\u0027 và \u0027Tương đối đáp ứng\u0027 có Mean Difference = -0,54874 (p \u003c 0,001). Diễn giải nào đúng?","a":["Nhóm rất khó khăn có hài lòng cao hơn","Nhóm tương đối đáp ứng được có điểm hài lòng trung bình cao hơn nhóm rất khó khăn 0,55 điểm có ý nghĩa","Áp lực tài chính không ảnh hưởng đến sự hài lòng","Tài chính là nguyên nhân trực tiếp kéo giảm sự hài lòng"],"correct":1,"explain":"Dấu chênh lệch âm (A - B \u003c 0) cho thấy nhóm A (Rất khó khăn) thấp hơn nhóm B (Tương đối đáp ứng) có ý nghĩa thống kê tuyệt vời."},{"q":"Tuyến lệnh SPSS chuẩn xác để chạy phép kiểm Independent Samples T-test là gì?","a":["Analyze → Compare Means → One-Way ANOVA","Analyze → Regression → Linear","Analyze → Compare Means → Independent-Samples T Test","Analyze → Correlate → Bivariate"],"correct":2,"explain":"Independent-Samples T Test nằm trong phân nhóm Compare Means."},{"q":"Trong hộp thoại Options của One-way ANOVA trên SPSS, hai tùy chọn nào là quan trọng nhất để phục vụ báo cáo luận văn?","a":["Descriptive \u0026 Homogeneity of variance test","Welch \u0026 Means plot","Exclude cases analysis by analysis","Tất cả các lựa chọn trên"],"correct":0,"explain":"Descriptive cung cấp số liệu mô tả (N, Mean, SD) và Homogeneity test cung cấp Levene\u0027s Test bắt buộc."},{"q":"Hàm Excel tương đương để tính trị xác suất p-value của kiểm định T-test hai mẫu độc lập là:","a":["=T.TEST(vung_1, vung_2, 2, 2)","=AVERAGE(vung_1)","=CORREL(vung_1, vung_2)","=COUNTIF(vung_1, 1)"],"correct":0,"explain":"Công thức hàm T.TEST của Excel yêu cầu vùng dữ liệu nhóm 1, vùng dữ liệu nhóm 2, số phía kiểm định (2 phía) và giả định phương sai (2 = đồng nhất)."},{"q":"Công cụ Excel nào cung cấp trực tiếp bảng ANOVA Single Factor chuẩn xác?","a":["PivotTable","Analysis ToolPak (Data Analysis)","Data Validation","Conditional Formatting"],"correct":1,"explain":"Analysis ToolPak cung cấp đầy đủ các thuật toán thống kê suy luận bao gồm ANOVA Single Factor."},{"q":"Biến Sự hài lòng chung \u0027SHL\u0027 là trung bình số học của các câu Likert 1-5. Trong SPSS, thuộc tính \u0027Measure\u0027 của biến này phải khai báo là gì?","a":["Nominal","Ordinal","Scale","String"],"correct":2,"explain":"Điểm trung bình số học là dữ liệu định lượng liên tục, trong SPSS bắt buộc phải khai báo là Scale."},{"q":"Sự khác biệt thực hành (Practical Significance) khác với sự khác biệt thống kê (Statistical Significance) như thế nào trong y học lâm sàng?","a":["Khác biệt thống kê chỉ dựa vào p \u003c 0,05; còn khác biệt thực hành đánh giá mức độ chênh lệch có thực sự tạo ra cải thiện lâm sàng/quản lý đáng kể không.","Hai khái niệm này hoàn toàn giống nhau.","Khác biệt thực hành có độ tin cậy thống kê cao hơn.","Khác biệt thống kê luôn luôn quan trọng hơn."],"correct":0,"explain":"p \u003c 0,05 chỉ cho thấy sự khác biệt không phải do ngẫu nhiên. Trị số chênh lệch thực tế (Mean Difference) mới quyết định giá trị can thiệp lâm sàng."},{"q":"Dược sĩ chuyên khoa báo cáo kết quả: \u0027SHL khác biệt có ý nghĩa thống kê theo thời gian bệnh (Welch = 8,516; p \u003c 0,001)\u0027. Nhận định ứng dụng quản lý nào sau đây là phù hợp?","a":["Cần xóa bỏ nhóm bệnh nhân lâu năm","Cần xây dựng quy trình hướng dẫn tư vấn sử dụng thuốc và chăm sóc hỗ trợ chuyên biệt cho nhóm bệnh nhân mới","Phải chuyển toàn bộ bệnh nhân sang phác đồ điều trị khác","Thời gian mắc bệnh kéo dài chắc chắn quyết định sự không hài lòng"],"correct":1,"explain":"Biến thời gian mắc bệnh giúp phân tầng đối tượng. Nhóm mới mắc chưa quen quy trình và có gánh nặng tâm lý lớn cần được ưu tiên chăm sóc hỗ trợ."}],"chapter-03":[{"q":"1. Mục đích quan trọng nhất của việc làm sạch dữ liệu trước khi phân tích là gì?","a":["Để loại bỏ các kết quả không theo ý muốn của nhà nghiên cứu nhằm tạo ra số liệu đẹp.","Để đảm bảo dữ liệu phản ánh chính xác thực tế lâm sàng, loại bỏ các nhiễu do lỗi kỹ thuật.","Để tự động tăng hệ số tin cậy Cronbach\u0027s Alpha lên mức \u003e 0.8.","Để giảm bớt cỡ mẫu cho SPSS xử lý nhanh hơn."],"correct":1,"explain":"Làm sạch nhằm kiểm soát chất lượng, loại bỏ nhiễu kỹ thuật chứ tuyệt đối không phải là hành vi ngụy tạo số liệu."},{"q":"2. Hành vi nào dưới đây được xem là vi phạm đạo đức nghiên cứu khi xử lý dữ liệu?","a":["Sử dụng lệnh Select Cases để tạm ẩn một nhóm bệnh án nghi ngờ lỗi.","Loại bỏ hoàn toàn một phiếu khảo sát vì bệnh nhân đánh điểm 5 cho toàn bộ các câu thuận và nghịch.","Tự ý sửa điểm Likert từ 2 thành 4 để làm tăng p-value lên mức có ý nghĩa thống kê.","Đảo chiều mã số (Recode) đối với các câu hỏi có ngữ nghĩa tiêu cực."],"correct":2,"explain":"Tự ý thay đổi bản chất dữ liệu để đạt mục đích cá nhân (chạy ra số đẹp) là hành vi ngụy tạo dữ liệu nghiêm trọng."},{"q":"3. Biến \u0027NhomTuoi\u0027 được khai báo trong Variable View có mã 1 (Dưới 18), 2 (18-60), 3 (Trên 60). Xuất hiện một dòng có mã \u00274\u0027. Đây thuộc nhóm lỗi gì?","a":["Lỗi dữ liệu khuyết thiếu (Missing Data).","Giá trị ngoài phạm vi (Out of Range).","Lỗi logic lâm sàng (Clinical Logic Error).","Lỗi phương sai không đồng nhất."],"correct":1,"explain":"Số 4 nằm ngoài hệ thống khai báo mã số từ 1 đến 3 nên được gọi là giá trị ngoài phạm vi biên."},{"q":"4. Khai báo Giới tính = Nam, nhưng có chẩn đoán ghi nhận \u0027Viêm lộ tuyến cổ tử cung\u0027. Đây là lỗi gì?","a":["Lỗi thiếu nhất quán trên thang đo.","Giá trị ngoài phạm vi.","Dữ liệu ngoại lai (Outlier).","Lỗi logic lâm sàng/hành chính."],"correct":3,"explain":"Nam giới không thể mắc bệnh lý chuyên khoa phụ khoa của nữ. Đây là lỗi xung đột logic sinh học cơ bản."},{"q":"5. Bệnh nhân chọn mức \u00275\u0027 cho tất cả 30 câu hỏi trong bảng khảo sát, kể cả câu thuận và câu hỏi gài đảo nghịch. Điều này phản ánh vấn đề gì?","a":["Bệnh nhân hoàn toàn khỏe mạnh và rất hài lòng.","Phiếu thiếu nhất quán do bệnh nhân đánh lụi, không đọc câu hỏi.","Lỗi của phần mềm SPSS khi nạp dữ liệu từ Excel.","Đây là phiếu dữ liệu hoàn toàn bình thường."],"correct":1,"explain":"Việc đánh cùng một mức điểm cho các câu hỏi mang ý nghĩa đối lập nhau chứng tỏ người trả lời không nghiêm túc."},{"q":"6. Tính năng nào trong Microsoft Excel giúp NGĂN CHẶN ngay lập tức việc người dùng gõ nhầm điểm 4 thành 44 trong cột thang đo Likert?","a":["Conditional Formatting","Auto Filter","Data Validation","VLOOKUP"],"correct":2,"explain":"Data Validation cho phép tạo quy tắc (ví dụ: Whole number từ 1 đến 5), nếu gõ sai, Excel sẽ hiện cảnh báo và chặn lệnh nhập."},{"q":"7. Trong Excel, tính năng nào giúp tự động nhuộm màu nền đỏ để cảnh báo các dòng có điểm Likert vượt trần (\u003e 5)?","a":["Data Validation","Conditional Formatting (Highlight Cells Rules)","Pivot Table","Sort \u0026 Filter"],"correct":1,"explain":"Định dạng có điều kiện (Conditional Formatting) tự động theo dõi giá trị ô, khi ô đạt điều kiện (\u003e5) nó sẽ tự đổi màu để thu hút sự chú ý."},{"q":"8. Công thức Excel nào thường dùng để đếm số lần xuất hiện của mã bệnh nhân (ID), từ đó phát hiện các hồ sơ bị nhập trùng lặp 2 lần?","a":["=SUM()","=IFERROR()","=COUNTIF()","=AVERAGE()"],"correct":2,"explain":"Hàm COUNTIF đếm số lần lặp lại của một mã ID. Nếu kết quả đếm được lớn hơn 1, nghĩa là ID đó đã bị nhập trùng lặp."},{"q":"9. Bộ lọc AutoFilter (Ctrl + Shift + L) trong Excel hỗ trợ làm sạch dữ liệu chủ yếu như thế nào?","a":["Nó tự động tính trung bình cộng cho các ô được chọn.","Hiển thị danh sách các giá trị duy nhất trong cột, giúp phát hiện nhanh các ký tự lạ hoặc khoảng trắng thừa.","Nó thay thế phần mềm SPSS trong việc chạy T-Test.","Nó tự động xóa bỏ các dòng bị lỗi."],"correct":1,"explain":"Mở menu thả xuống của Filter sẽ hiển thị toàn bộ giá trị đang tồn tại. Nếu thấy xuất hiện \u0027Nam\u0027, \u0027Nữ\u0027, và \u0027N \u0027 thì ta dễ dàng phát hiện lỗi gõ dư khoảng trắng."},{"q":"10. Lệnh Frequencies trong SPSS chủ yếu được sử dụng với mục đích gì trong bước làm sạch dữ liệu?","a":["Để tìm mối liên hệ nhân quả giữa 2 biến liên tục.","Kiểm tra biểu đồ Histogram rà soát tỷ lệ khuyết thiếu (Missing) và các giá trị định danh ngoài biên.","Để đảo ngược các biến Likert tiêu cực.","Để phân tích nhân tố khám phá EFA."],"correct":1,"explain":"Frequencies thống kê tần suất xuất hiện của từng mã. Giúp bạn thấy rõ bao nhiêu phần trăm dữ liệu đang là Missing hoặc nhận các giá trị lạ."},{"q":"11. Lệnh Crosstabs trong SPSS đặc biệt hiệu quả để phát hiện loại lỗi nào?","a":["Đo lường hệ số Cronbach\u0027s Alpha.","Xóa bỏ các hồ sơ bị trùng lặp ID.","Lỗi logic chéo giữa 2 biến định danh (VD: Giới tính và Bệnh lý tuyến tiền liệt).","Chỉnh sửa cỡ chữ trên biểu đồ."],"correct":2,"explain":"Bảng chéo (Crosstabs) kết hợp các dòng và cột. Bất kỳ giá trị lớn hơn 0 nào nằm ở ô giao thoa phi logic (VD: Nữ x Phì đại tuyến tiền liệt) đều báo hiệu có lỗi."},{"q":"12. Trong SPSS, khi muốn tạm thời tách riêng nhóm bệnh nhân có thời gian mắc bệnh \u003e 10 năm để kiểm tra chi tiết mà KHÔNG làm xóa mất các bệnh nhân khác, ta dùng lệnh nào?","a":["Delete Cases","Select Cases (Option: If condition is satisfied)","Split File","Sort Cases"],"correct":1,"explain":"Select Cases tạo ra một bộ lọc an toàn, các dòng không thỏa mãn chỉ bị gạch chéo ngoài Data View chứ không bị xóa vĩnh viễn."},{"q":"13. Học viên thao tác Select Cases để kiểm tra bệnh nhân Nam. Sau đó QUÊN không thao tác chọn lại \u0027All cases\u0027 mà mang file đi chạy EFA. Hậu quả là gì?","a":["Phần mềm SPSS sẽ báo lỗi và tắt đột ngột.","Các phân tích EFA tiếp theo sẽ chỉ chạy trên tập bệnh nhân Nam, làm sai lệch hoàn toàn kết quả nghiên cứu tổng thể.","Dữ liệu bệnh nhân Nữ bị xóa vĩnh viễn khỏi ổ cứng.","Không ảnh hưởng gì vì SPSS tự động hiểu để khôi phục All cases khi chạy EFA."],"correct":1,"explain":"Đây là lỗi cực kỳ phổ biến. Nếu bộ lọc Select Cases vẫn đang bật, mọi phân tích thống kê tiếp theo đều chỉ áp dụng cho nhóm đang được lọc."},{"q":"14. Lệnh nào trong SPSS dùng để chuyển đổi (đảo chiều) thang đo Likert hoặc gom các độ tuổi thành các nhóm tuổi?","a":["Compute Variable","Crosstabs","Recode (into Same/Different Variables)","Explore"],"correct":2,"explain":"Recode (Mã hóa lại) là công cụ chuyên dụng để chuyển đổi các giá trị cũ thành các giá trị mới theo luật (Ví dụ: Old 1 -\u003e New 5)."},{"q":"15. Tại sao các nhà nghiên cứu thường cài cắm \u0027câu hỏi gài\u0027 (Control questions) trong bảng khảo sát dài?","a":["Để làm bảng hỏi dài ra, trông có vẻ khoa học hơn.","Để lọc và loại bỏ các đối tượng trả lời bừa bãi, thiếu chú tâm đọc nội dung câu hỏi.","Để tăng tỷ lệ hồi đáp của bệnh nhân.","Để thay thế cho việc xin ý kiến hội đồng y đức."],"correct":1,"explain":"Câu hỏi gài giúp xác định xem người điền có tính nhất quán trong suy nghĩ hay chỉ đánh dấu tùy tiện từ trên xuống dưới."},{"q":"16. Trong xây dựng thang đo, \u0027câu hỏi đảo nghịch\u0027 (Reverse worded item) được hiểu là gì?","a":["Câu hỏi được in ở mặt sau của tờ giấy.","Câu hỏi có chủ đích mang ngữ nghĩa tiêu cực/phủ định nhằm yêu cầu người đọc phải tư duy ngược lại với xu hướng chung.","Câu hỏi có thể bỏ qua không cần trả lời.","Câu hỏi dạng mở (Open-ended question)."],"correct":1,"explain":"Câu hỏi nghịch (Ví dụ: \u0027Thuốc này gây nhiều tác dụng phụ khó chịu\u0027) yêu cầu người cảm thấy tốt phải đánh điểm THẤP, ngược với quy luật chung."},{"q":"17. Hậu quả của việc KHÔNG thao tác đảo mã (Recode) các câu hỏi đảo nghịch trước khi tính Cronbach\u0027s Alpha là gì?","a":["Không ảnh hưởng vì SPSS thông minh có khả năng tự động nhận diện câu hỏi đảo.","Hệ số Cronbach\u0027s Alpha sẽ bị kéo tụt xuống thảm hại (thậm chí âm) do máy tính cho rằng có sự phân tán bất thường trong nhân tố.","Chỉ làm sai lệch tên biến trong bảng kết quả.","SPSS từ chối thực hiện thuật toán tính toán Alpha."],"correct":1,"explain":"Cronbach\u0027s Alpha đo độ tin cậy đồng nhất. Nếu bạn cộng dồn cả điểm thuận và điểm nghịch, tổng phương sai bị triệt tiêu, khiến hệ số Alpha sụp đổ."},{"q":"18. Đối với thang đo Likert 5 mức độ, một bệnh nhân đánh điểm 2 cho câu hỏi nghịch. Áp dụng công thức chuẩn hóa, giá trị mới nạp vào EFA sẽ là:","a":["4","3","5","2"],"correct":0,"explain":"Công thức đảo mã là Y_new = (Max + Min) - X_old = (5 + 1) - 2 = 4."},{"q":"19. Khi phát hiện dữ liệu lỗi (VD: Giới tính = 3), nhưng bạn KHÔNG THỂ truy xuất lại hồ sơ bệnh án gốc để xác minh, hành động chuẩn mực nhất là gì?","a":["Tự ý sửa thành 1 (Nam) vì tỷ lệ Nam thường cao hơn.","Xóa toàn bộ dòng bệnh án của bệnh nhân đó lập tức.","Chấp nhận chuyển giá trị ô đó thành khoảng trống và khai báo là dữ liệu khuyết (System Missing).","Dùng tính năng random ngẫu nhiên ra 1 hoặc 2."],"correct":2,"explain":"Nếu không có bằng chứng đối chiếu, bạn bắt buộc phải công nhận đó là dữ liệu khuyết thiếu. Không được tự ý sáng tác ra số liệu mới."},{"q":"20. Cảnh báo lỗi \"SPSS Error 1099\" trong quá trình thao tác phần mềm thường mang ý nghĩa gì?","a":["File Excel bạn nhập vào chứa quá 1099 dòng dữ liệu.","Do người nhập liệu đánh sai định dạng chữ thành số.","Là lỗi hệ thống liên quan đến xác thực bản quyền phần mềm (License), không phải lỗi do dữ liệu bẩn.","Báo hiệu hệ số Cronbach\u0027s Alpha nhỏ hơn 0.5."],"correct":2,"explain":"Mã lỗi 1099 trong SPSS là mã cảnh báo không tìm thấy License bản quyền hợp lệ từ máy chủ, hoàn toàn không liên quan đến lỗi sai của số liệu nghiên cứu."}],"chapter-02":[{"q":"Trong nghiên cứu đánh giá sự hài lòng của bệnh nhân về dịch vụ của khoa Dược lâm sàng, thang đo nào là tối ưu và phổ biến nhất để đo lường các ý kiến/thái độ?","a":["B. Thang đo tỷ lệ (Scale) liên tục từ 1 đến 100%.","C. Thang đo Likert 5 mức độ (Từ rất không đồng ý đến rất đồng ý) khai báo Ordinal.","D. Chỉ sử dụng câu hỏi tự luận mở."],"correct":2,"explain":""},{"q":"Học viên Nguyễn Tiến Đạt nhập dữ liệu biến sự hài lòng 5 mức Likert (HQ1) của bệnh nhân. Trình duyệt nhập liệu thô của anh có xuất hiện một giá trị \"33\". Khi chuyển dữ liệu này chạy tính điểm trung bình (Mean) trong SPSS, điều gì xảy ra?","a":["B. SPSS sẽ bỏ qua giá trị này và không đưa vào tính toán.","C. Giá trị \"33\" trở thành giá trị ngoại lệ cực lớn (Outlier), kéo điểm trung bình của toàn nhân tố tăng vọt một cách phi lý.","D. SPSS tự động loại bỏ bệnh nhân này khỏi toàn bộ nghiên cứu."],"correct":2,"explain":""},{"q":"Quy tắc an toàn sống còn khi thực hiện chuyển đổi, gộp nhóm một biến định lượng (ví dụ Tuổi) thành biến phân nhóm trong SPSS là:","a":["B. Sử dụng lệnh Recode into Different Variables để ghi nhận giá trị phân nhóm vào một biến mới độc lập và bảo vệ biến thô ban đầu.","C. Thực hiện phân chia trực tiếp trên phần mềm Microsoft Excel thô rồi xóa biến thô cũ.","D. Không bao giờ gộp nhóm dữ liệu vì sẽ làm hỏng kết quả."],"correct":1,"explain":""},{"q":"Trong SPSS, hai thuộc tính Name và Label trong Variable View khác nhau như thế nào?","a":["B. Name dùng để đặt tên cho người dùng, Label dành cho máy tính đọc.","C. Hai thuộc tính này hoàn toàn giống nhau, viết sao cũng được.","D. Name là nhãn còn Label là giá trị số của biến."],"correct":0,"explain":""},{"q":"Trong Excel, công thức nào tạo biến nhị phân \"SHL_NhiPhan\" dựa trên nguyên tắc: Người bệnh cho điểm sự hài lòng chung (SHL) lớn hơn hoặc bằng 4.0 là \"Hài lòng\" (mã hóa = 1), dưới 4.0 là \"Chưa hài lòng\" (mã hóa = 0)?","a":["B. =AVERAGE(SHL_cell)","C. =COUNTIF(SHL_cell, 4)","D. =SUM(SHL_cell)"],"correct":0,"explain":""},{"q":"Một biến số ghi nhận \"Tác dụng phụ của thuốc\" với các giá trị: \"Đau đầu\", \"Buồn nôn\", \"Chóng mặt\", \"Mệt mỏi\". Thang đo (Measure) nào trong SPSS là phù hợp nhất cho biến này?","a":["B. Ordinal","C. Nominal","D. String (Định dạng chuỗi ký tự tự do)"],"correct":2,"explain":""},{"q":"Biến \"Nhóm tuổi\" được mã hóa: 1 = Dưới 30 tuổi, 2 = Từ 30 đến 50 tuổi, 3 = Trên 50 tuổi. Khi khai báo trong Variable View, thuộc tính Decimals của biến này nên đặt là bao nhiêu?","a":["B. 1","C. 0","D. Hệ thống tự động thiết lập không đổi được."],"correct":2,"explain":""},{"q":"Tại sao mã số bệnh nhân (ID) không được khai báo là thang đo Scale trong SPSS mặc dù nó được biểu thị bằng các số như 001, 002, 003?","a":["B. Vì biến ID chỉ mang tính chất định danh phân biệt, các phép toán như cộng, trừ, tính trung bình trên biến này hoàn toàn vô nghĩa.","C. Vì biến ID phải luôn được lưu dưới dạng chữ (String) để tiết kiệm bộ nhớ.","D. Vì biến ID không có giá trị phân tích trong kiểm định ANOVA."],"correct":1,"explain":""},{"q":"Để phát hiện nhanh các lỗi nhập liệu thô trong SPSS (ví dụ: gõ nhầm số \"6\" vào cột Likert chỉ có giá trị từ 1 đến 5), công cụ thống kê mô tả nào nên được chạy đầu tiên?","a":["B. Bảng tần suất (Frequencies)","C. Phân tích tương quan Pearson (Correlate)","D. Hồi quy tuyến tính bội (Regression)"],"correct":1,"explain":""},{"q":"Khi khai báo biến \"Nồng độ thuốc trong huyết tương (mcg/ml)\" của một loại kháng sinh, thang đo (Measure) nào trong SPSS là chính xác nhất?","a":["B. Ordinal","C. Scale","D. System-missing"],"correct":2,"explain":""},{"q":"Trong Microsoft Excel, tổ hợp phím tắt/phím tuần tự nào giúp mở nhanh hộp thoại Data Validation để cấu hình chặn lỗi?","a":["B. Nhấn giữ Ctrl + Shift + L","C. Nhấn giữ Alt + F11","D. Nhấn tuần tự Alt -\u003e H -\u003e M -\u003e C"],"correct":0,"explain":""},{"q":"Khi nhập liệu biến \"Khả năng chi trả của bệnh nhân\" với các mức: 1=Rất khó khăn, 2=Khó khăn, 3=Bình thường, 4=Không khó khăn. Đây thuộc loại thang đo nào?","a":["B. Ordinal","C. Scale","D. Binary"],"correct":1,"explain":""},{"q":"Lỗi \"SPSS 1099\" thường xuất hiện do nguyên nhân chủ yếu nào sau đây trong quá trình chuẩn bị dữ liệu?","a":["B. Xung đột kiểu dữ liệu giữa Excel và SPSS khi nạp file (ví dụ cột Numeric nhưng chứa chuỗi ký tự lạ như \"N/A\", \"Trống\",...).","C. Do máy tính chạy SPSS không kết nối Internet.","D. Do cỡ mẫu khảo sát của học viên nhỏ hơn 30 bệnh nhân."],"correct":1,"explain":""},{"q":"Khi chuẩn bị nhập liệu trên Excel (.xlsx) để nạp thẳng vào SPSS, dòng đầu tiên của bảng tính (Row 1) nên chứa thông tin gì?","a":["B. Tên viết tắt của các biến số (Name), không có dấu, không khoảng trắng, không ký tự đặc biệt.","C. Họ tên học viên và thông tin người hướng dẫn khoa học.","D. Ngày giờ bắt đầu tiến hành nhập dữ liệu thô."],"correct":1,"explain":""},{"q":"Biến \"Thời gian mắc bệnh mãn tính\" được đo bằng số tháng thực tế. Thang đo phù hợp trong SPSS là gì, và nếu muốn chuyển thành 3 nhóm (Dưới 12 tháng, 12-60 tháng, Trên 60 tháng) ta dùng chức năng nào?","a":["B. Thang đo Scale, sử dụng chức năng Recode into Different Variables.","C. Thang đo Nominal, sử dụng chức năng Sort Cases.","D. Thang đo Scale, sử dụng chức năng Select Cases."],"correct":1,"explain":""},{"q":"Thuộc tính Missing trong Variable View của SPSS đóng vai trò gì trong phân tích thống kê?","a":["B. Khai báo các giá trị quy ước là \"dữ liệu thiếu\" (ví dụ: gõ số 99 khi bệnh nhân từ chối trả lời) để SPSS loại trừ giá trị này khi tính toán mà không cần xóa dòng dữ liệu.","C. Tự động điền các giá trị trung bình vào những ô bị bỏ trống.","D. Khóa chặn lỗi đánh máy không cho người dùng gõ phím."],"correct":1,"explain":""},{"q":"Bạn đang nhập liệu cho biến định lượng \"Chỉ số huyết áp tâm thu\". Nếu nhập nhầm chữ \"H\" thay vì số 120 vào một ô, và cột đó trong SPSS được khai báo kiểu Numeric, SPSS sẽ hiển thị ô đó thế nào?","a":["B. Tự động quy đổi chữ \"H\" thành giá trị số trung bình của cả cột.","C. Hiển thị một dấu chấm (.) biểu thị dữ liệu bị khuyết thiếu (System Missing).","D. Báo lỗi liên tục và khóa toàn bộ tệp dữ liệu không cho thao tác tiếp."],"correct":2,"explain":""},{"q":"Khi thiết kế bộ câu hỏi Likert 5 mức độ khảo sát bệnh nhân, tại sao giảng viên khuyên nên hạn chế sử dụng câu hỏi có cấu trúc phủ định (ví dụ: \"Nhân viên khoa Dược không có thái độ thờ ơ\")?","a":["B. Vì câu hỏi phủ định dễ gây nhầm lẫn cho bệnh nhân khi đánh giá, đồng thời đòi hỏi học viên phải mất thêm bước đảo điểm nghịch đảo cực kỳ dễ sai sót trước khi kiểm định Cronbach\u0027s Alpha.","C. Vì câu hỏi phủ định làm tăng độ lệch chuẩn của thang đo một cách phi lý.","D. Vì quy chuẩn của tạp chí khoa học quốc tế cấm dùng câu hỏi phủ định."],"correct":1,"explain":""},{"q":"Trong SPSS, sau khi kiểm định độ tin cậy Cronbach\u0027s Alpha đạt chuẩn, nếu bạn muốn tính Điểm trung bình gộp nhân tố \"Hiệu quả điều trị\" (HQ) từ 5 câu hỏi thành phần từ HQ1 đến HQ5, bạn sẽ sử dụng lệnh nào?","a":["B. Sử dụng Analyze -\u003e Correlate -\u003e Bivariate.","C. Sử dụng Transform -\u003e Recode into Same Variables.","D. Sử dụng Analyze -\u003e Descriptive Statistics -\u003e Frequencies."],"correct":0,"explain":""},{"q":"Vì sao việc khai báo gán nhãn giá trị (Values) trong SPSS là bắt buộc đối với các biến phân nhóm (như Giới tính, Nhóm tuổi, Phác đồ điều trị)?","a":["B. Để khi xuất các bảng tần số (Frequencies) hay bảng chéo (Crosstabs), SPSS sẽ hiển thị đúng tên nhãn chữ (ví dụ: \"Đơn trị\", \"Phối hợp 2 thuốc\") thay vì các con số vô hồn 1, 2, giúp dễ dàng sao chép báo cáo vào luận văn.","C. Để SPSS tự động phát hiện và loại bỏ các giá trị nhập liệu sai lệch.","D. Để bảo đảm thông tin cá nhân của bệnh nhân tham gia khảo sát hoàn toàn được mã hóa bảo mật."],"correct":1,"explain":""}],"chapter-09":[{"q":"Trong mô hình hồi quy đánh giá HQ, TD, QL, TT, DV, CP tác động đến SHL, biến SHL đóng vai trò gì?","a":["Biến độc lập","Biến phụ thuộc","Biến nhiễu","Biến kiểm soát"],"correct":1,"explain":"SHL (Sự hài lòng chung) là kết quả chịu sự tác động, được dự báo bởi các biến khác, do đó nó là Biến phụ thuộc (Y)."},{"q":"Mục đích chính của phân tích hồi quy tuyến tính bội trong nghiên cứu này là gì?","a":["Đánh giá độ tin cậy của bảng hỏi.","Gom nhóm các câu hỏi thành các nhân tố.","Đánh giá đồng thời mức độ tác động của các nhân tố đến sự hài lòng.","So sánh sự khác biệt về sự hài lòng giữa nam và nữ."],"correct":2,"explain":"Hồi quy bội đánh giá sự tác động đồng thời của nhiều biến độc lập lên một biến phụ thuộc. Các đáp án khác thuộc về Cronbach\u0027s Alpha, EFA, và T-test."},{"q":"Để kiểm tra hiện tượng đa cộng tuyến, ta sử dụng chỉ số nào trong bảng Coefficients?","a":["Sig. (P-value)","Durbin-Watson","VIF","Adjusted R Square"],"correct":2,"explain":"VIF (Variance Inflation Factor) là hệ số phóng đại phương sai, dùng để chẩn đoán hiện tượng đa cộng tuyến. Ngưỡng thường dùng là VIF \u003c 2 hoặc \u003c 10."},{"q":"Chỉ số nào cho biết mức độ giải thích (theo % tỷ lệ) của toàn bộ mô hình đối với sự biến thiên của biến phụ thuộc trong mẫu tổng thể?","a":["R Square ($R^2$)","Adjusted R Square ($R^2$ hiệu chỉnh)","Durbin-Watson","Unstandardized B"],"correct":1,"explain":"Trong hồi quy bội, ta luôn đọc Adjusted R Square ($R^2$ hiệu chỉnh) vì nó phản ánh chính xác hơn sự phù hợp của mô hình khi có nhiều biến độc lập, tránh sự thổi phồng của R Square thông thường."},{"q":"Để tính cỡ mẫu tối thiểu cho hồi quy tuyến tính bội, với mô hình có 6 biến độc lập, công thức $N \\\\ge 50 + 8p$ cho ra kết quả bao nhiêu?","a":["50","58","98","150"],"correct":2,"explain":"Với p = 6 (số biến độc lập). N \u003e= 50 + 8 * 6 = 50 + 48 = 98."},{"q":"Biến QL (Năng lực quản lý) có Beta chuẩn hóa = 0,390, Sig. = 0,000. Cách diễn giải nào sau đây phù hợp nhất trong luận văn?","a":["QL chắc chắn là nguyên nhân gốc rễ gây ra SHL.","QL có mối liên hệ thuận chiều có ý nghĩa thống kê với SHL và có tác động tương đối mạnh trong mô hình.","QL không có ý nghĩa thống kê đối với SHL.","Khi QL tăng 1 đơn vị, SHL tăng đúng 0,390 đơn vị."],"correct":1,"explain":"Vì Sig = 0.000 \u003c 0.05 nên có ý nghĩa thống kê. Beta dương (0.390) thể hiện tác động thuận chiều. Không được khẳng định \u0027nguyên nhân gốc rễ\u0027 trong nghiên cứu cắt ngang."},{"q":"Trong bảng ANOVA, giá trị Sig. = 0,125 (lớn hơn 0,05) có ý nghĩa gì?","a":["Mô hình hồi quy rất tốt và có thể suy rộng ra tổng thể.","Cần chạy thêm kiểm định T-test.","Mô hình hồi quy xây dựng KHÔNG phù hợp với dữ liệu tổng thể, giả thuyết bị bác bỏ.","Chỉ có biến Chi phí là không phù hợp."],"correct":2,"explain":"Kiểm định ANOVA (kiểm định F) đánh giá sự phù hợp của toàn bộ mô hình. Nếu Sig \u003e 0.05, mô hình không có ý nghĩa thống kê, không thể dùng để dự báo."},{"q":"Trong bảng Coefficients, biến Chi phí (CP) có Sig. = 0.650. Bạn phải làm gì?","a":["Kết luận CP là nhân tố tác động mạnh nhất.","Kết luận không có bằng chứng thống kê cho thấy CP tác động đến SHL trong mô hình này.","Sửa lại dữ liệu để Sig \u003c 0.05.","Thay đổi phương pháp sang phân tích nhân tố EFA."],"correct":1,"explain":"Sig. \u003e 0.05 tức là không có ý nghĩa thống kê. Ta không được quyền bóp méo số liệu mà phải tôn trọng sự thật khách quan này và kết luận như phương án B."},{"q":"Để so sánh TẦM QUAN TRỌNG hay MỨC ĐỘ TÁC ĐỘNG của các nhân tố (xem nhân tố nào tác động mạnh nhất), ta nhìn vào cột nào trong bảng Coefficients?","a":["Unstandardized B (Hệ số B chưa chuẩn hóa)","Standardized Beta (Hệ số Beta chuẩn hóa)","t (Giá trị t)","Sig. (P-value)"],"correct":1,"explain":"Beta chuẩn hóa loại bỏ đơn vị đo lường ban đầu, cho phép so sánh sức mạnh tác động tương đối giữa các biến độc lập với nhau."},{"q":"Hệ số Durbin-Watson dùng để kiểm định giả định nào của hồi quy?","a":["Phân phối chuẩn của phần dư.","Tính độc lập của phần dư (không có tự tương quan bậc 1).","Đa cộng tuyến.","Phương sai sai số thay đổi."],"correct":1,"explain":"Durbin-Watson (DW) kiểm tra hiện tượng tự tương quan. Giá trị từ 1.5 đến 2.5 cho thấy phần dư độc lập, mô hình thỏa mãn điều kiện."},{"q":"Biểu đồ Normal P-P Plot of Regression Standardized Residual cho thấy các điểm phân tán nằm bám sát dọc theo đường chéo. Điều này kết luận gì?","a":["Mô hình bị đa cộng tuyến.","Phần dư có phân phối xấp xỉ chuẩn, thỏa mãn điều kiện hồi quy.","Dữ liệu có nhiều giá trị ngoại lai (outlier) cần xóa bỏ.","Không thể kết luận được gì."],"correct":1,"explain":"Trong P-P Plot, nếu các điểm nằm sát đường chéo, ta kết luận giả định về phân phối chuẩn của phần dư được thỏa mãn."},{"q":"Biểu đồ Scatterplot (ZRESID ở Y và ZPRED ở X) dùng để kiểm tra giả định gì?","a":["Phân phối chuẩn.","Đa cộng tuyến.","Phương sai phần dư đồng đều (không đổi).","Tính tuyến tính giữa X và Y."],"correct":2,"explain":"Scatterplot của phần dư chuẩn hóa và giá trị dự đoán chuẩn hóa được dùng để kiểm tra tính đồng đều của phương sai. Nếu điểm phân bố ngẫu nhiên, không tạo hình phễu hay đường cong thì giả định được thỏa mãn."},{"q":"Một học viên chạy hồi quy và thu được Adjusted R Square = 0.05 (5%). Nhận xét nào là đúng chuyên môn lâm sàng nhất?","a":["Mô hình quá tốt, giải thích được 5% vấn đề.","Mô hình rất yếu, giải thích được rất ít sự biến thiên của SHL. Cần xem xét lại các nhân tố lâm sàng bị bỏ sót.","Mô hình bị lỗi SPSS.","Cần tiếp tục chạy để ra 50%."],"correct":1,"explain":"R2 hiệu chỉnh = 5% là rất thấp. Nghĩa là 95% sự thay đổi của Sự hài lòng do các yếu tố khác chưa được đưa vào mô hình gây ra. Học viên cần thảo luận về các giới hạn này."},{"q":"Biến Thái độ (TD) có Unstandardized B = 0.45, Sig = 0.001. Có thể viết phương trình hồi quy chứa biến TD như thế nào?","a":["$SHL = ... + 0.001 * TD + ...$","$SHL = ... + 0.45 * TD + ...$","$TD = 0.45 * SHL$","$SHL = ... + (0.45 / 0.001) * TD + ...$"],"correct":1,"explain":"Phương trình hồi quy được viết bằng hệ số B chưa chuẩn hóa (Unstandardized B). Dạng phương trình là Y = B0 + B1*X1 + ... Nên là + 0.45*TD."},{"q":"Một lỗi THƯỜNG GẶP nhất khi học viên khai báo biến cho lệnh Regression là gì?","a":["Không chọn mục Durbin-Watson.","Đưa cả biến Giới tính (Biến phân loại định danh) trực tiếp vào ô Independent mà chưa mã hóa Dummy.","Quên lưu file dữ liệu.","Mở nhầm file Word."],"correct":1,"explain":"Hồi quy tuyến tính bội thông thường (như bài học) yêu cầu các biến độc lập phải là định lượng. Nếu muốn đưa biến phân loại (như Giới tính, Nghề nghiệp) vào, phải tạo biến giả (Dummy variable) hoặc dùng ANOVA."},{"q":"Khi hội đồng hỏi: \u0027Tại sao em kết luận biến HQ tác động thuận chiều đến SHL?\u0027, bạn sẽ chỉ vào chỉ số nào?","a":["Chỉ số VIF","Dấu (+) của hệ số Beta hoặc B trong bảng Coefficients.","Chỉ số Sig. của ANOVA.","Chỉ số R Square."],"correct":1,"explain":"Dấu của hệ số B hoặc Beta cho biết chiều tác động. Dấu (+) là thuận chiều (HQ tăng thì SHL tăng), dấu (-) là ngược chiều."},{"q":"Nếu có 1 biến độc lập có VIF = 15. Bạn nên xử lý như thế nào?","a":["Mặc kệ nó, vì Sig \u003c 0.05 là được.","Loại bỏ biến này khỏi mô hình và chạy lại hồi quy, vì nó gây ra đa cộng tuyến nghiêm trọng.","Tăng cỡ mẫu lên gấp đôi.","Cộng biến đó vào biến phụ thuộc."],"correct":1,"explain":"VIF \u003e 10 biểu hiện đa cộng tuyến mạnh. Cách xử lý tiêu chuẩn là loại bỏ biến gây đa cộng tuyến và chạy lại mô hình."},{"q":"Câu nào CHƯA CHÍNH XÁC khi viết kết luận trong Luận văn CK1 về Hồi quy cắt ngang?","a":["Kết quả phân tích cho thấy Thái độ phục vụ là yếu tố dự báo mạnh nhất sự hài lòng.","Có mối liên hệ thuận chiều giữa Hiệu quả điều trị và Sự hài lòng.","Nghiên cứu chứng minh Thái độ phục vụ kém chắc chắn gây ra sự không hài lòng của bệnh nhân.","Mô hình giải thích được 55% sự biến thiên của biến phụ thuộc."],"correct":2,"explain":"Nghiên cứu cắt ngang (Cross-sectional) khảo sát tại 1 thời điểm nên KHÔNG THỂ chứng minh mối quan hệ nhân quả (Causation - \u0027gây ra\u0027). Chỉ được dùng từ \u0027dự báo\u0027, \u0027liên quan\u0027, \u0027tác động trong mô hình\u0027."},{"q":"Bạn tiến hành chạy hồi quy tuyến tính trong SPSS theo thao tác: Analyze -\u003e Regression -\u003e ...?","a":["Correlate","Linear","Binary Logistic","Factor"],"correct":1,"explain":"Đường dẫn đúng cho Hồi quy tuyến tính bội là Analyze -\u003e Regression -\u003e Linear."},{"q":"Theo quan điểm lâm sàng và quản lý chất lượng Dược, nếu biến \u0027Thông tin thuốc\u0027 (TT) bị loại khỏi mô hình (do Sig \u003e 0.05), bạn diễn giải thế nào?","a":["Việc cung cấp thông tin thuốc cho bệnh nhân là vô nghĩa, nên bỏ qua khâu này.","Bệnh nhân hoàn toàn không quan tâm đến thuốc họ đang uống.","Trong phạm vi mẫu nghiên cứu này, việc nhân viên cung cấp thông tin thuốc chưa thể hiện sự ảnh hưởng rõ rệt đến mức độ hài lòng chung. Cần khảo sát sâu hơn ở các nghiên cứu sau.","Dữ liệu đã bị nhập sai 100%."],"correct":2,"explain":"Không có ý nghĩa thống kê không đồng nghĩa với việc vô nghĩa trong thực tiễn lâm sàng. Cần giải thích cẩn trọng, giới hạn trong phạm vi mẫu nghiên cứu và gợi ý nghiên cứu sâu hơn, thay vì đưa ra kết luận cực đoan."}],"chapter-06":[{"q":"1. Trong nghiên cứu y dược, kiểm định Cronbach’s Alpha dùng để đánh giá điều gì?","a":["A. Giá trị của thang đo (Validity - đo có đúng không)","B. Độ tin cậy của thang đo (Reliability - đo có nhất quán không)","C. Mức độ ảnh hưởng của biến độc lập lên biến phụ thuộc","D. Khả năng đại diện của mẫu nghiên cứu"],"correct":1,"explain":"Cronbach\u0027s Alpha đo lường độ tin cậy (tính nhất quán nội bộ) của thang đo. Ví dụ: Các câu hỏi cùng đo lường sự hài lòng có xu hướng trả lời giống nhau không."},{"q":"2. Học viên A đưa cả 5 biến: Giới tính, Tuổi, Trình độ, Phác đồ và Điểm đánh giá (Likert) vào chạy Cronbach\u0027s Alpha một lần. Thao tác này là:","a":["A. Đúng, để kiểm tra sự đồng thuận của mẫu.","B. Sai, vì Cronbach\u0027s Alpha chỉ dùng cho các biến định lượng đo lường cùng một khái niệm (như Likert).","C. Sai, vì SPSS không cho phép đưa biến Tuổi vào.","D. Đúng, nếu mẫu lớn hơn 150."],"correct":1,"explain":"Lỗi rất thường gặp! Cronbach\u0027s Alpha tuyệt đối không dùng cho các biến nhân khẩu học (định danh, thứ bậc) hoặc biến không cùng đo 1 khái niệm mẹ."},{"q":"3. Khi kiểm tra thang đo \u0027Cảm nhận Chi phí\u0027 (CP) gồm 4 biến CP1, CP2, CP3, CP4. Học viên phải làm gì trên SPSS?","a":["A. Chạy gộp chung với các biến Hiệu quả (HQ) để so sánh.","B. Chạy riêng nhóm biến CP1 đến CP4 trong một lệnh Reliability Analysis.","C. Chạy từng biến riêng lẻ (chạy 4 lần).","D. Tính trung bình 4 biến rồi mới chạy Cronbach\u0027s Alpha."],"correct":1,"explain":"Trong luận văn, phải chạy Cronbach\u0027s Alpha LẦN LƯỢT cho TỪNG nhóm biến (từng thang đo) để kiểm tra độ tin cậy nội bộ của khái niệm đó."},{"q":"4. Mức giá trị tối thiểu của hệ số Cronbach’s Alpha để thang đo được coi là \u0027chấp nhận được\u0027 trong các nghiên cứu cơ bản là bao nhiêu?","a":["A. \u003e 0.3","B. \u003e 0.5","C. \u003e 0.6","D. \u003e 0.9"],"correct":2,"explain":"Tiêu chuẩn thông dụng nhất: Alpha \u003e 0.6 là chấp nhận được, \u003e 0.7 là tốt, \u003e 0.8 là rất tốt."},{"q":"5. Khi đọc bảng Item-Total Statistics, chỉ số \u0027Corrected Item-Total Correlation\u0027 (Tương quan biến - tổng hiệu chỉnh) phải đạt mức tối thiểu là bao nhiêu để giữ lại biến?","a":["A. 0.05","B. 0.3","C. 0.6","D. 1.0"],"correct":1,"explain":"Biến có Corrected Item-Total Correlation \u003e= 0.3 mới được xem là có tương quan thuận chiều đủ mạnh với phần còn lại của thang đo."},{"q":"6. Nếu anh chị chạy SPSS mà QUÊN đánh dấu mục \u0027Scale if item deleted\u0027 trong nút Statistics, hậu quả là gì?","a":["A. SPSS sẽ báo lỗi Error 1099.","B. SPSS không hiện ra chỉ số Cronbach\u0027s Alpha.","C. Không biết được việc loại bỏ một biến cụ thể sẽ làm Alpha tăng hay giảm để ra quyết định.","D. Chỉ số Alpha sẽ bị tính sai."],"correct":2,"explain":"Mục này quyết định việc tạo ra 2 cột cực kỳ quan trọng ở bảng Item-Total Statistics giúp ta biết có nên xóa biến hay không."},{"q":"7. Giả sử thang đo \u0027Thái độ phục vụ\u0027 (TD) có hệ số Alpha = 0.820. Biến TD3 có hệ số tương quan biến tổng là 0.45. Cột \u0027Alpha if Item Deleted\u0027 của TD3 là 0.810. Quyết định đúng là:","a":["A. Xóa TD3 vì hệ số tương quan 0.45 \u003c 0.820.","B. Giữ lại TD3 vì hệ số tương quan \u003e 0.3 và nếu xóa nó đi, Alpha chung bị giảm (từ 0.820 xuống 0.810).","C. Xóa TD3 vì Alpha if Item Deleted (0.810) nhỏ hơn Alpha chung (0.820).","D. Chạy lại bảng hỏi."],"correct":1,"explain":"Biến TD3 đang đóng góp tích cực cho thang đo. Nếu xóa nó, Alpha giảm, do đó BẮT BUỘC phải giữ lại."},{"q":"8. Thang đo \u0027Hiệu quả\u0027 (HQ) có Alpha = 0.650. Cột \u0027Alpha if Item Deleted\u0027 của biến HQ2 là 0.720. Điều này có nghĩa là gì?","a":["A. Biến HQ2 rất tốt, cần giữ lại.","B. Nếu bỏ biến HQ2 ra khỏi mô hình, độ tin cậy của thang đo sẽ tăng lên mức Tốt (0.720).","C. Biến HQ2 là biến phụ thuộc.","D. Dữ liệu bị lỗi nhập liệu."],"correct":1,"explain":"Con số 0.720 cho biết \u0027Tương lai\u0027 của thang đo nếu loại bỏ biến HQ2. Xóa HQ2 giúp thang đo tốt hơn."},{"q":"9. Một biến có hệ số Tương quan biến-tổng (Corrected Item-Total) bằng 0.25 (Nhỏ hơn 0.3). Tuy nhiên, đây là biến đo lường khái niệm quan trọng nhất của lâm sàng. Anh/chị nên:","a":["A. Xóa ngay lập tức vì quy định thống kê là bắt buộc.","B. Xem xét lại ý nghĩa chuyên môn, kiểm tra lỗi nhập liệu, có thể xem xét GIỮ LẠI thay vì loại cơ học.","C. Tự sửa số liệu cho nó tăng lên 0.35.","D. Đổi thang đo từ Likert 5 điểm sang 3 điểm."],"correct":1,"explain":"Nguyên tắc sống còn: Không loại biến cơ học. Ý nghĩa lâm sàng/chuyên môn luôn đứng trên các chỉ số thống kê."},{"q":"10. Sau khi quyết định loại biến HQ2 khỏi thang đo HQ (gồm HQ1 đến HQ5). Bước tiếp theo để lấy số liệu viết luận văn là gì?","a":["A. Lấy Alpha cũ cộng thêm số \u0027Alpha if item deleted\u0027.","B. Báo cáo bằng số Alpha cũ (lúc chưa xóa).","C. Chạy lại lệnh Reliability Analysis cho 4 biến còn lại (HQ1, HQ3, HQ4, HQ5) để lấy kết quả chính thức.","D. Mang luôn 4 biến vào chạy Hồi quy."],"correct":2,"explain":"Khi cấu trúc thang đo thay đổi (xóa biến), phải chạy lại SPSS để lấy kết quả Alpha và Tương quan biến-tổng mới nhất để báo cáo."},{"q":"11. \u0027Tương quan biến - tổng hiệu chỉnh\u0027 (Corrected Item-Total Correlation) thực chất là phép toán nào trên Excel?","a":["A. Hàm SUM().","B. Hàm AVERAGE() giữa các biến.","C. Hàm CORREL() tương quan giữa biến đó và TỔNG điểm của các biến còn lại trong cùng thang đo.","D. Hàm VLOOKUP()."],"correct":2,"explain":"Nó đo lường xem sự biến thiên của 1 câu hỏi có đi cùng hướng với TỔNG sự biến thiên của các câu hỏi còn lại trong thang đo hay không."},{"q":"12. Nếu Cronbach\u0027s Alpha của anh chị ra kết quả âm (VD: -0.125), nguyên nhân khả dĩ nhất là gì?","a":["A. Mẫu nghiên cứu quá nhỏ.","B. Có câu hỏi bị mã hóa ngược chiều nhưng anh chị quên đảo mã (Recode) trên SPSS trước khi chạy.","C. Không cài đặt đủ Add-ons trong SPSS.","D. SPSS hết bản quyền."],"correct":1,"explain":"Câu hỏi ngược chiều (Ví dụ: 1-Rất hài lòng... nhưng câu khác lại 1-Rất thất vọng) sẽ làm hệ số tương quan bị âm, kéo Alpha xuống âm."},{"q":"13. Khi đọc kết quả cho hội đồng bảo vệ, cách nói nào sau đây là CHUẨN XÁC NHẤT?","a":["A. \u0027Mô hình nghiên cứu của em có độ tin cậy 0.850\u0027.","B. \u0027Thang đo Sự hài lòng đạt độ tin cậy Cronbach\u0027s Alpha là 0.850, nhỏ nhất của tương quan biến tổng là 0.42 \u003e 0.3\u0027.","C. \u0027Cronbach Alpha của toàn bộ 30 câu hỏi là 0.850\u0027.","D. \u0027Em giữ lại biến vì p-value \u003c 0.05\u0027."],"correct":1,"explain":"Phải nói rõ Alpha của \u0027Thang đo\u0027 nào cụ thể, và cung cấp chứng cứ \u0027Tương quan biến tổng\u0027 (Corrected item-total correlation) để bảo vệ việc giữ biến."},{"q":"14. Một thang đo chỉ có 2 biến quan sát (Ví dụ CP1 và CP2). Khi chạy Cronbach\u0027s Alpha thì điều gì xảy ra?","a":["A. SPSS không cho chạy.","B. Vẫn chạy được, nhưng Cronbach\u0027s Alpha thường không ổn định, nên dùng hệ số tương quan Pearson giữa 2 biến.","C. Kết quả luôn bằng 1.","D. Alpha luôn nhỏ hơn 0.3."],"correct":1,"explain":"Alpha nhạy cảm với số lượng biến. Chỉ có 2 biến thì đo lường bằng tương quan Pearson (Bivariate Correlation) thường hợp lý hơn."},{"q":"15. Nếu giá trị \u0027Cronbach\u0027s Alpha if Item Deleted\u0027 của một biến tăng RẤT ÍT so với Alpha chung (Ví dụ: Từ 0.850 lên 0.852). Anh chị nên:","a":["A. Xóa ngay để tối ưu hóa con số.","B. Giữ lại, vì việc tăng 0.002 là quá nhỏ, không đáng để đánh đổi việc mất đi một thông tin nghiên cứu.","C. Thêm vào một biến giả.","D. Xóa biến phụ thuộc."],"correct":1,"explain":"Việc hy sinh dữ liệu thực tế chỉ để đổi lấy 0.00x phần trăm độ tin cậy là không đáng. Chỉ xóa khi nó thực sự cải thiện rõ rệt mô hình."},{"q":"16. Trong cửa sổ Reliability Analysis, tùy chọn \u0027Model\u0027 mặc định là Alpha. Ngoài ra SPSS còn các mô hình nào (dù ít dùng ở CK1)?","a":["A. T-test, ANOVA.","B. Split-half, Guttman, Parallel.","C. Logistic Regression.","D. K-means."],"correct":1,"explain":"Các mô hình như Split-half (chia đôi thang đo) cũng dùng để đo độ tin cậy nhưng Cronbach\u0027s Alpha là chuẩn mực phổ biến nhất."},{"q":"17. Bước phân tích Cronbach\u0027s Alpha nằm ở đâu trong quy trình xử lý số liệu chuẩn?","a":["A. Sau Hồi quy tuyến tính.","B. Trước khi làm sạch số liệu.","C. Sau khi làm sạch số liệu (Lọc Missing, Outlier) và TRƯỚC phân tích nhân tố EFA.","D. Là bước cuối cùng của luận văn."],"correct":2,"explain":"Quy trình chuẩn: Làm sạch data -\u003e Cronbach\u0027s Alpha -\u003e EFA -\u003e Tương quan Pearson -\u003e Hồi quy."},{"q":"18. Sự khác biệt giữa Cronbach\u0027s Alpha và Phân tích nhân tố khám phá (EFA) là gì?","a":["A. Alpha kiểm tra độ nhất quán (cùng nhóm), EFA kiểm tra xem chúng có thực sự tạo thành các nhóm nhân tố (giá trị hội tụ/phân biệt) hay không.","B. Alpha dùng cho biến định lượng, EFA dùng cho biến định danh.","C. Không có sự khác biệt, dùng cái nào cũng được.","D. EFA đo lường p-value còn Alpha thì không."],"correct":0,"explain":"Alpha đo Reliability (Độ tin cậy). EFA đo Validity (Giá trị). Hai công cụ này bổ trợ cho nhau."},{"q":"19. Bệnh nhân đánh giá 1 thang đo \u0027Thời gian chờ\u0027 rất thấp (toàn 1 và 2 điểm). Hệ số Cronbach\u0027s Alpha có bị thấp theo không?","a":["A. Có, vì điểm thấp thì Alpha thấp.","B. Không. Alpha chỉ đo \u0027sự biến thiên cùng chiều\u0027 (nhất quán). Nếu bệnh nhân nào cũng đánh giá 1, 2 điểm giống nhau ở các câu, Alpha vẫn cao.","C. Bị lỗi phần mềm.","D. Alpha sẽ biến thành số âm."],"correct":1,"explain":"Rất nhiều người nhầm lẫn! Điểm trung bình thấp (thực trạng kém) KHÔNG liên quan đến độ tin cậy. Nhất quán đánh giá điểm kém thì Alpha vẫn rất cao."},{"q":"20. Lời khuyên cuối cùng: Nếu một bảng hỏi được thiết kế sơ sài, copy chắp vá, câu hỏi tối nghĩa. Công cụ Cronbach\u0027s Alpha sẽ xử lý thế nào?","a":["A. SPSS sẽ tự động sửa lỗi câu từ.","B. Alpha sẽ chỉ ra câu hỏi đó thấp, nhưng không thể \u0027phục hồi\u0027 dữ liệu. Garbage in, garbage out.","C. SPSS sẽ báo bảng hỏi copy.","D. Alpha sẽ luôn ra kết quả \u003e 0.8."],"correct":1,"explain":"Thống kê không có phép thuật. Thiết kế biến/bảng hỏi tồi từ đầu (Garbage in) thì kết quả chạy ra cũng vô nghĩa (Garbage out)."}],"chapter-04":[{"q":"Câu 1. Trong mô hình \"HQ, TD, QL, TT, DV, CP tác động đến SHL\", mệnh đề nào sau đây biểu diễn giả thuyết H1?","a":["B. Sự hài lòng tác động đến Hiệu quả điều trị.","C. Hiệu quả điều trị là biến nền.","D. Sự hài lòng tác động đến Giới tính."],"correct":0,"explain":""},{"q":"Câu 2. Khi thiết lập khai báo biến trong Variable View của SPSS, cột \"Values\" có chức năng gì?","a":["B. Để gán nhãn giải thích cho các con số (VD: 1 = Nam, 2 = Nữ).","C. Để xóa dữ liệu bị Missing.","D. Để nhập trực tiếp số liệu của bệnh nhân."],"correct":1,"explain":""},{"q":"Câu 3. Học viên A thu về dữ liệu và phát hiện giả thuyết H6 (Chi phí tác động đến Sự hài lòng) bị bác bỏ (p \u003e 0.05). Học viên A nên làm gì?","a":["B. Xóa bỏ nhân tố Chi phí khỏi mô hình vì coi như nghiên cứu thất bại.","C. Giữ nguyên và biện luận dựa trên thực tế lâm sàng (VD: Bệnh nhân có BHYT 100% nên không bận tâm chi phí).","D. Chạy lại EFA để loại bỏ bớt biến quan sát."],"correct":2,"explain":""},{"q":"Câu 4. Trong Excel, tính năng nào giúp \"khóa\" ô nhập liệu, chỉ cho phép nhập các số từ 1 đến 5 để tránh sai sót gõ nhầm?","a":["B. VLOOKUP","C. Data Validation","D. Format Painter"],"correct":2,"explain":""},{"q":"Câu 5. Trong mô hình: HQ, TD, QL, TT, DV, CP ➔ SHL, biến SHL đóng vai trò là gì?","a":["B. Biến nền","C. Mã missing","D. Biến phụ thuộc"],"correct":3,"explain":""},{"q":"Câu 6. Lỗi \"trộn nhân tố\" (Double-barreled) trong thiết kế bảng hỏi Likert là gì?","a":["B. Câu hỏi mang ý nghĩa phủ định kép.","C. Không có đáp án mức độ trung lập.","D. Đưa 2 khái niệm khác nhau vào cùng 1 câu hỏi để đánh giá."],"correct":3,"explain":""},{"q":"Câu 7. Thang đo định danh (Nominal) trong SPSS phù hợp để khai báo cho các biến nào dưới đây?","a":["B. Điểm trung bình hài lòng.","C. Chi phí điều trị (VNĐ).","D. Trình độ học vấn (Cấp 1, Cấp 2, Đại học)."],"correct":0,"explain":""},{"q":"Câu 8. Lệnh nào trong SPSS được sử dụng để tính điểm trung bình (Mean) cho một nhân tố dựa trên các biến quan sát (VD: HQ1 đến HQ5)?","a":["B. Data \u003e Sort Cases","C. Transform \u003e Compute Variable","D. Analyze \u003e Correlate"],"correct":2,"explain":""},{"q":"Câu 9. Kiểm định Cronbach\u0027s Alpha và EFA trên SPSS có thể giúp khắc phục một bảng hỏi được thiết kế sai (trộn nhân tố, khó hiểu) ngay từ đầu không?","a":["B. Có, nhưng chỉ khi cỡ mẫu lớn hơn 500.","C. Không thể. Bảng hỏi sai sẽ cho ra dữ liệu vô nghĩa (Garbage in, Garbage out).","D. Không thể, cần dùng phần mềm Excel mới sửa được."],"correct":2,"explain":""},{"q":"Câu 10. Trong các nghiên cứu sự hài lòng ngành Dược, nhân tố \"Chi phí\" (CP) thường được hiểu đúng về chuyên môn là gì?","a":["B. Sự cảm nhận của bệnh nhân về tính hợp lý, minh bạch của chi phí.","C. Mức lương hàng tháng của bệnh nhân.","D. Lợi nhuận của nhà thuốc bệnh viện."],"correct":1,"explain":""},{"q":"Câu 11. Tại sao KHÔNG NÊN đưa bất kỳ biến nào vào mô hình nghiên cứu chỉ vì \"có sẵn dữ liệu thu thập được\"?","a":["B. Vì phần mềm SPSS chỉ chạy được tối đa 5 biến.","C. Vì biến đó sẽ luôn làm giảm ý nghĩa thống kê (p-value).","D. Vì Excel không hỗ trợ lưu trữ số lượng biến lớn."],"correct":0,"explain":""},{"q":"Câu 12. Khi khai báo tên biến (Name) trong phần mềm SPSS, quy tắc nào sau đây là ĐÚNG?","a":["B. Có thể chứa khoảng trắng (VD: Gioi tinh).","C. Không dấu, không khoảng trắng, không ký tự đặc biệt ở đầu (VD: GioiTinh).","D. Bắt buộc phải viết hoa toàn bộ (VD: GIOITINH)."],"correct":2,"explain":""},{"q":"Câu 13. Hành động nào sau đây là thiết yếu trước khi tiến hành chạy phân tích hồi quy trên SPSS?","a":["B. Bỏ qua các giá trị khuyết thiếu (missing data) vì SPSS tự bù đắp.","C. Kiểm tra rà soát dữ liệu lỗi, Missing data bằng bảng tần số (Frequencies).","D. Nhân đôi số lượng mẫu (Copy-Paste) để kết quả đẹp hơn."],"correct":2,"explain":""},{"q":"Câu 14. Trong nghiên cứu khảo sát, biến nền / biến kiểm soát thường KHÔNG bao gồm yếu tố nào?","a":["B. Phác đồ điều trị đang sử dụng.","C. Trình độ học vấn.","D. Mức độ hiệu quả lâm sàng (Đo bằng thang đo Likert)."],"correct":3,"explain":""},{"q":"Câu 15. Hàm nào trong Excel tương đương với lệnh Compute ➔ MEAN(HQ1, HQ2, HQ3, HQ4, HQ5) trong SPSS?","a":["B. =COUNT()","C. =AVERAGE()","D. =MEDIAN()"],"correct":2,"explain":""},{"q":"Câu 16. Do đặc thù \"nghiên cứu cắt ngang\" (Cross-sectional) chỉ phản ánh tính thời điểm, người viết luận văn nên tránh sử dụng từ ngữ nào khi kết luận?","a":["B. \"Gây ra\" hoặc \"Quyết định\"","C. \"Có xu hướng tác động\"","D. \"Yếu tố dự báo\""],"correct":1,"explain":""},{"q":"Câu 17. Việc ĐẦU TIÊN học viên cần làm trước khi thu thập dữ liệu và nhập liệu là gì?","a":["B. Mở ngay phần mềm SPSS và gõ bừa vào Data View.","C. Xin số liệu giả từ khóa trước.","D. Báo cáo tiến độ với hội đồng."],"correct":0,"explain":""},{"q":"Câu 18. Nếu nhân viên đánh máy nhầm giá trị \"33\" vào cột Giới tính (quy ước 1=Nam, 2=Nữ) trong Excel. Khi Import file này vào SPSS, điều gì sẽ xảy ra?","a":["B. SPSS sẽ chặn không cho Import file Excel.","C. SPSS vẫn Import số 33, nếu không dùng bảng tần số kiểm tra, kết quả phân tích sẽ sai lệch hoàn toàn.","D. SPSS tự động quy số 33 về giá trị Missing (Khuyết)."],"correct":2,"explain":""},{"q":"Câu 19. Biến Trình độ học vấn (1: Cấp 1, 2: Cấp 2, 3: Cấp 3, 4: Đại học/Sau ĐH) nên được khai báo Measure là gì trong SPSS?","a":["B. Ordinal (Thứ bậc)","C. Scale (Định lượng liên tục)","D. String (Chuỗi văn bản)"],"correct":1,"explain":""},{"q":"Câu 20. Tên đề tài y dược chuẩn mực cho một luận văn CK1 cần phản ánh đủ các yếu tố nào?","a":["B. Tên phương pháp thống kê và Phần mềm sử dụng.","C. Chỉ cần nêu rõ vấn đề nghiên cứu.","D. Đối tượng + Vấn đề + Không gian (Cơ sở y tế) + Thời gian."],"correct":3,"explain":""}],"chapter-11":[{"q":"Khi biến phụ thuộc là SHL_NhiPhan gồm 0 = Chưa hài lòng và 1 = Hài lòng, nên dùng phương pháp nào?","a":["Hồi quy tuyến tính bội","Hồi quy Logistic nhị phân","Cronbach’s Alpha","Phân tích nhân tố khám phá EFA"],"correct":1,"explain":"Do biến phụ thuộc là nhị phân (chỉ nhận hai giá trị 0 và 1), hồi quy Logistic nhị phân là phép kiểm tối ưu bắt buộc."},{"q":"Quy tắc tạo biến SHL_NhiPhan trong ngữ cảnh bài giảng này là gì?","a":["SHL ≥ 4 mã hóa 1 = Hài lòng","SHL ≥ 4 mã hóa 0 = Hài lòng","SHL \u003c 4 mã hóa 1 = Hài lòng","SHL luôn luôn mã hóa bằng 1"],"correct":0,"explain":"Theo quy ước khoa học Y tế Việt Nam, điểm trung bình từ 4.00 trở lên thể hiện đạt sự hài lòng rõ rệt (mã hóa là 1)."},{"q":"Exp(B) trong hồi quy Logistic nhị phân được hiểu chính xác là gì?","a":["Hệ số Beta chuẩn hóa","Hệ số xác định R Square","Tỷ số số chênh (Odds Ratio)","Giá trị trung bình nhóm"],"correct":2,"explain":"Exp(B) là e lũy thừa B, đại diện cho tỷ số số chênh (Odds Ratio) trong hồi quy Logistic."},{"q":"Nếu Exp(B) của QL là 3.49 và Sig. \u003c 0.05, diễn giải nào sau đây phù hợp nhất cho luận văn?","a":["Khi QL tăng 1 điểm, điểm hài lòng chung tăng 3.49 điểm.","Khi QL tăng 1 điểm, cơ may (Odds) bệnh nhân đạt hài lòng tăng gấp 3.49 lần.","Xác suất hài lòng chắc chắn tăng chính xác 349% cho mọi bệnh nhân.","Yếu tố QL gây ra sự hài lòng tuyệt đối cho bệnh nhân."],"correct":1,"explain":"Exp(B) \u003e 1 chỉ ra mức tăng cơ may (Odds) của nhóm sự kiện quan tâm khi biến độc lập tăng 1 đơn vị."},{"q":"Kiểm định Hosmer and Lemeshow có Sig. = 0.624 (\u003e 0.05) gợi ý điều gì?","a":["Mô hình bị sai nghiêm trọng.","Mô hình phù hợp tốt với dữ liệu thực tế thu thập.","Tất cả các biến độc lập đều không có ý nghĩa.","Cần phải tăng cỡ mẫu gấp đôi mới kết luận được."],"correct":1,"explain":"Hosmer-Lemeshow là kiểm định độ phù hợp mô hình, ta mong muốn Sig. \u003e 0.05 để mô hình khớp dữ liệu."},{"q":"Nếu yếu tố TT có Exp(B) = 1.083; Sig. = 0.657 và khoảng tin cậy 95% chứa giá trị 1, nên kết luận như thế nào?","a":["TT chắc chắn làm tăng hài lòng.","TT làm tăng điểm SHL lên 1.083 điểm.","Chưa có bằng chứng thống kê cho thấy TT liên quan đến cơ may hài lòng của bệnh nhân.","Bắt buộc phải xóa TT khỏi bộ dữ liệu gốc ngay."],"correct":2,"explain":"Do Sig. \u003e 0.05 và khoảng tin cậy chứa giá trị 1, ta kết luận chưa có bằng chứng thống kê liên quan."},{"q":"Nagelkerke R Square là 0.573 cho biết điều gì?","a":["Mô hình giải thích chính xác 57.3% biến thiên điểm hài lòng theo nghĩa tuyến tính.","Mô hình hồi quy Logistic giải thích được khoảng 57.3% sự biến thiên của khả năng hài lòng.","Mô hình chỉ dự báo đúng 57.3% các trường hợp.","Mô hình bị nhiễu thông tin 57.3%."],"correct":1,"explain":"Nagelkerke R Square là Pseudo R-square phản ánh mức độ giải thích tương đối của mô hình Logistic."},{"q":"Tuyến lệnh chuẩn để chạy Binary Logistic Regression trong SPSS là gì?","a":["Analyze -\u003e Correlate -\u003e Bivariate...","Analyze -\u003e Regression -\u003e Linear...","Analyze -\u003e Regression -\u003e Binary Logistic...","Transform -\u003e Compute Variable..."],"correct":2,"explain":"Đường dẫn chính xác là Analyze -\u003e Regression -\u003e Binary Logistic."},{"q":"Trong bảng Classification Table, trị số Overall Percentage = 83.2% nghĩa là gì?","a":["Mô hình bị sai lệch 83.2%.","Mô hình dự báo và phân loại chính xác 83.2% tổng số trường hợp thực tế.","83.2% bệnh nhân chắc chắn hài lòng tuyệt đối.","Mô hình chỉ có ý nghĩa với 83.2% cỡ mẫu khảo sát."],"correct":1,"explain":"Classification Table cho biết tỷ lệ phân loại dự báo chính xác tổng thể của mô hình so với thực tế."},{"q":"Tương tác nào trong SPSS giúp khai báo biến định tính (như Giới tính, Trình độ) trong hồi quy Logistic?","a":["Nút Options...","Nút Categorical...","Nút Save...","Nút Define Simple..."],"correct":1,"explain":"Nút Categorical... dùng để chuyển đổi và gán nhóm tham chiếu cho các biến định tính đưa vào mô hình."},{"q":"Hàm IF nào trong Excel giúp tạo biến nhị phân SHL_NhiPhan từ điểm hài lòng SHL tại ô H2?","a":["=IF(H2\u003c4, 1, 0)","=IF(H2\u003e=4, 1, 0)","=IF(H2\u003e4, 1, 0)","=SUM(H2:H10)"],"correct":1,"explain":"IF(H2\u003e=4, 1, 0) chuyển điểm từ 4.00 trở lên thành 1, ngược lại dưới 4.00 thành 0."},{"q":"Khi đọc bảng Dependent Variable Encoding, nhóm \u00271 = Hài lòng\u0027 có mã là 1 nghĩa là gì?","a":["Mô hình đang dự báo xác suất bệnh nhân chưa hài lòng.","Mô hình đang dự báo xác suất bệnh nhân thuộc nhóm hài lòng.","Mô hình bị lỗi gán nhãn mã hóa.","Mô hình không quan tâm đến nhóm hài lòng."],"correct":1,"explain":"Gán mã 1 có nghĩa SPSS đang tính toán xác suất xảy ra sự kiện 1 (Hài lòng)."},{"q":"Để phòng tránh lỗi xung đột định dạng biến hoặc lỗi nhập liệu thô, ta nên thực hiện lệnh gì trước khi phân tích hồi quy?","a":["Compute Variable","Descriptive Statistics -\u003e Frequencies để quét dọn lỗi","Linear Regression","EFA ngay lập tức"],"correct":1,"explain":"Chạy Frequencies giúp rà quét phát hiện các giá trị nhập lỗi (ngoài phạm vi 0-1) để kịp thời sửa chữa."},{"q":"Nếu một biến độc lập có Sig. = 0.002 và Exp(B) = 2.138, mối liên hệ này là gì?","a":["Liên quan nghịch chiều có ý nghĩa thống kê.","Liên quan thuận chiều có ý nghĩa thống kê rất rõ nét.","Không có mối liên hệ nào đáng chú ý.","Mối liên quan tuyến tính yếu."],"correct":1,"explain":"Do Sig. \u003c 0.05 và Exp(B) \u003e 1, yếu tố liên quan thuận chiều làm tăng cơ may hài lòng."},{"q":"Lỗi thiết lập định Measure nào thường gặp khi học viên tạo xong biến SHL_NhiPhan?","a":["Để nguyên Scale thay vì chuyển về Nominal.","Để Nominal thay vì chuyển về Scale.","Để Ordinal.","Để định dạng chuỗi ký tự String."],"correct":0,"explain":"SHL_NhiPhan là biến nhị phân định danh, bắt buộc phải khai báo Measure là Nominal trong SPSS."},{"q":"Với thiết kế nghiên cứu cắt ngang, từ ngữ diễn giải nào sau đây là chuẩn mực lâm sàng nhất?","a":["Yếu tố đó quyết định/gây ra sự hài lòng của bệnh nhân.","Yếu tố đó có liên quan/có xu hướng ảnh hưởng thuận chiều đến khả năng hài lòng.","Mô hình chứng minh quan hệ nhân quả tuyệt đối giữa các biến.","Bệnh viện chắc chắn thay đổi 100% khi áp dụng mô hình."],"correct":1,"explain":"Nghiên cứu cắt ngang thu thập số liệu tại 1 thời điểm, chỉ kết luận liên quan hoặc xu hướng ảnh hưởng, tránh khẳng định nhân quả tuyệt đối."},{"q":"Trong Excel, làm thế nào để tính tỷ lệ hài lòng (SHL_NhiPhan = 1) của dải ô từ I2 đến I221?","a":["=COUNTIF(I2:I221, 1)/COUNTA(I2:I221)","=SUM(I2:I221)","=AVERAGE(I2:I221)","=MIN(I2:I221)"],"correct":0,"explain":"Công thức đếm số ô bằng 1 chia cho tổng số ô khảo sát cho ra tỷ lệ phần trăm hài lòng chính xác."},{"q":"Trị số Wald trong bảng Variables in the Equation có vai trò gì?","a":["Đo lường mức độ đa cộng tuyến.","Đánh giá vai trò đóng góp/ý nghĩa của từng biến độc lập trong mô hình.","Đo lường độ khớp dữ liệu của Hosmer-Lemeshow.","Dự báo xác suất phần trăm hài lòng."],"correct":1,"explain":"Chỉ số Wald bình phương tỷ lệ hệ số B chia sai số chuẩn S.E, dùng để đánh giá ý nghĩa đóng góp của biến."},{"q":"Sự khác biệt căn bản nhất giữa hồi quy tuyến tính bội và hồi quy Logistic nhị phân là gì?","a":["Khác biệt ở số lượng biến độc lập.","Khác biệt ở bản chất thang đo của biến phụ thuộc (Scale so với Nominal nhị phân).","Khác biệt ở cách gán nhãn Missing value.","Hai phương pháp hoàn toàn giống hệt nhau."],"correct":1,"explain":"Tuyến tính dùng cho biến phụ thuộc định lượng liên tục (Scale), Logistic dùng cho biến phụ thuộc nhị phân (Nominal 0/1)."},{"q":"Nhận xét hồi quy Logistic nhị phân trong luận văn CK1 cần cấu trúc theo mấy tầng?","a":["1 tầng: chỉ liệt kê số liệu.","2 tầng: số liệu và kết luận thống kê.","3 tầng: số liệu, kết luận thống kê và ý nghĩa lâm sàng/quản lý dược.","Không cần viết nhận xét chỉ cần chụp ảnh bảng biểu."],"correct":2,"explain":"Chuẩn học thuật luận văn tốt nghiệp luôn yêu cầu 3 tầng: Số liệu -\u003e Kết luận thống kê -\u003e Ứng dụng thực tiễn Y học/Quản lý dược."}],"chapter-01":[{"q":"1. Thiết kế nghiên cứu nào được coi là tiêu chuẩn vàng để chứng minh hiệu quả lâm sàng điều trị của một thuốc mới?","a":["A. Nghiên cứu cắt ngang mô tả.","B. Nghiên cứu bệnh chứng hồi cứu.","C. Thử nghiệm lâm sàng ngẫu nhiên có đối chứng (RCT).","D. Nghiên cứu thuần tập tiến cứu."],"correct":2,"explain":"RCT (Randomized Controlled Trial) có tính ngẫu nhiên hóa và kiểm soát nhóm chứng chặt chẽ, là tiêu chuẩn cao nhất xác lập mối liên hệ nhân quả hiệu quả thuốc."},{"q":"2. Một học viên tiến hành khảo sát mức độ hài lòng của 150 bệnh nhân tại khoa ngoại trú vào một buổi sáng cụ thể. Phác đồ chọn mẫu nào đang được sử dụng?","a":["A. Chọn mẫu ngẫu nhiên đơn.","B. Chọn mẫu thuận tiện (Phi xác suất).","C. Chọn mẫu phân tầng xác suất.","D. Chọn mẫu chùm."],"correct":1,"explain":"Tận dụng các đối tượng sẵn có, dễ tiếp cận tại một mốc thời gian là kỹ thuật chọn mẫu Thuận tiện (Convenience Sampling)."},{"q":"3. Nhược điểm cốt lõi nhất của nghiên cứu cắt ngang (Cross-sectional Study) trong dịch tễ học là gì?","a":["A. Thời gian nghiên cứu quá kéo dài.","B. Kinh phí thực hiện cực kỳ đắt đỏ.","C. Không thể xác định được trình tự thời gian trước sau giữa phơi nhiễm và bệnh trạng (Không chứng minh nhân quả).","D. Không thể áp dụng tính tỷ lệ phần trăm phân bố."],"correct":2,"explain":"Bởi vì cả phơi nhiễm và bệnh được đo lường cùng một thời điểm, ta không rõ yếu tố nào xuất hiện trước."},{"q":"4. Thang đo nào trong SPSS được quy ước cho biến định tính không có thứ bậc (Ví dụ: Giới tính Nam/Nữ)?","a":["A. Nominal Scale","B. Ordinal Scale","C. Scale","D. Interval Scale"],"correct":0,"explain":"Nominal là thang đo định danh, dùng để phân nhóm các giá trị không có tính chất hơn kém hoặc thứ bậc."},{"q":"5. Lệnh nào trên thanh công cụ SPSS giúp bạn lọc lấy một lượng mẫu bệnh án ngẫu nhiên từ bộ dữ liệu tổng?","a":["A. Transform -\u003e Compute Variable","B. Analyze -\u003e Descriptive Statistics -\u003e Frequencies","C. Data -\u003e Select Cases","D. Data -\u003e Split File"],"correct":2,"explain":"Đường dẫn Data -\u003e Select Cases cho phép người dùng chọn ngẫu nhiên (Random sample of cases) một phần dữ liệu."},{"q":"6. Điểm Likert từ 1 (Rất không đồng ý) đến 5 (Rất đồng ý) của từng câu hỏi khuyết lẻ được quy ước thuộc loại thang đo nào trong SPSS?","a":["A. Nominal Scale","B. Ordinal Scale","C. Scale","D. Ratio Scale"],"correct":1,"explain":"Mỗi câu hỏi Likert đơn lẻ có giá trị biểu thị mức độ hơn kém rõ rệt nên thuộc loại Ordinal (Thứ bậc)."},{"q":"7. Khi gộp trung bình cộng nhiều câu hỏi Likert cùng nhân tố để chạy kiểm định hồi quy, biến nhân tố trung bình đại diện sẽ có thuộc tính thang đo nào?","a":["A. Nominal Scale","B. Ordinal Scale","C. Scale (Định lượng liên tục)","D. Đơn thuần định danh"],"correct":2,"explain":"Điểm trung bình nhân tố (Mean) là biến liên tục số thực, được khai báo thuộc thang đo Scale trong SPSS."},{"q":"8. Trình độ suy thận của bệnh nhân chia thành Giai đoạn I, II, III thuộc loại thang đo nào?","a":["A. Nominal","B. Ordinal","C. Scale","D. Định lượng liên tục"],"correct":1,"explain":"Có sự phân bậc mức độ nghiêm trọng rõ ràng nhưng không đo bằng khoảng cách định lượng cụ thể, thuộc Ordinal."},{"q":"9. Hàm nào trong Excel được áp dụng để sinh số ngẫu nhiên phục vụ việc lấy mẫu thô thuận tiện?","a":["A. =AVERAGE()","B. =COUNTIF()","C. =RAND()","D. =SUM()"],"correct":2,"explain":"Hàm RAND() sinh các số thực ngẫu nhiên từ 0 đến dưới 1 hỗ trợ xáo trộn ngẫu nhiên dữ liệu."},{"q":"10. Để thực hiện phân tích nhân tố khám phá (EFA) ổn định, quy tắc tối thiểu cỡ mẫu cần đạt được là bao nhiêu?","a":["A. Chỉ cần tối thiểu 30 mẫu cho tất cả các nghiên cứu.","B. Tối thiểu 5 quan sát cho một biến quan sát (biến đo lường).","C. Phải lấy mẫu trên 1000 bệnh nhân.","D. Không có quy tắc liên quan."],"correct":1,"explain":"Trong EFA, cỡ mẫu tối thiểu thường yêu cầu tỷ lệ là 5 quan sát cho 1 biến quan sát ($n \\\\ge 5 \\ imes p$)."},{"q":"11. Công thức tính cỡ mẫu theo Green ($N \\\\ge 50 + 8p$) áp dụng cho phép kiểm thống kê nào?","a":["A. Kiểm định Chi-bình phương so sánh tỷ lệ.","B. Phân tích hồi quy tuyến tính bội (với p là số biến độc lập).","C. Kiểm định Independent Samples T-test.","D. Phân tích nhân tố khám phá EFA."],"correct":1,"explain":"Quy tắc Green ($50 + 8p$) ước tính cỡ mẫu tối thiểu để chạy mô hình hồi quy đa biến có ý nghĩa thống kê."},{"q":"12. Sai lệch lựa chọn (Selection Bias) thường xuất hiện nghiêm trọng nhất ở nhóm phương pháp chọn mẫu nào?","a":["A. Chọn mẫu ngẫu nhiên hệ thống.","B. Chọn mẫu xác suất phân tầng.","C. Chọn mẫu phi xác suất (Chọn mẫu thuận tiện).","D. Chọn mẫu ngẫu nhiên đơn."],"correct":2,"explain":"Chọn mẫu phi xác suất không đảm bảo mọi đối tượng đều có cơ hội được chọn, rất dễ thiên vị hoặc mất tính đại diện."},{"q":"13. Thiết kế nghiên cứu nào đi ngược chiều thời gian, lấy nhóm đối tượng bị bệnh và nhóm không bị bệnh ở hiện tại để tìm hiểu yếu tố tiếp xúc trong quá khứ?","a":["A. Nghiên cứu thuần tập tiến cứu.","B. Nghiên cứu bệnh chứng hồi cứu (Case-control).","C. Nghiên cứu mô tả cắt ngang.","D. Thử nghiệm lâm sàng ngẫu nhiên."],"correct":1,"explain":"Nghiên cứu bệnh chứng đi ngược thời gian để tìm hiểu nguyên nhân phơi nhiễm quá khứ của ca bệnh."},{"q":"14. Một nghiên cứu viên chia danh sách bệnh nhân thành 2 tầng: tầng bệnh ngoại trú và tầng bệnh nội trú, sau đó lấy mẫu ngẫu nhiên từ mỗi tầng. Đây là kỹ thuật gì?","a":["A. Chọn mẫu ngẫu nhiên đơn.","B. Chọn mẫu xác suất phân tầng (Stratified Sampling).","C. Chọn mẫu chùm.","D. Chọn mẫu thuận tiện."],"correct":1,"explain":"Sự phân chia quần thể thành các tầng riêng biệt trước khi rút mẫu ngẫu nhiên là chọn mẫu phân tầng."},{"q":"15. Nếu bộ dữ liệu nghiên cứu chỉ có 50 bệnh nhân nhưng học viên muốn thiết lập phân tích EFA cho bộ câu hỏi 30 biến quan sát, điều gì xảy ra?","a":["A. SPSS vẫn tự động chạy và cho kết quả chuẩn xác 100%.","B. Vi phạm nghiêm trọng cỡ mẫu tối thiểu của EFA, kết quả phân tích không đạt độ tin cậy khoa học.","C. Kết quả p-value sẽ tự động đạt tối ưu.","D. Phân mềm sẽ bị hỏng hoàn toàn không chạy được."],"correct":1,"explain":"Với 30 biến, EFA cần ít nhất $30 \\ imes 5 = 150$ mẫu. Việc chạy trên 50 mẫu sẽ làm sai lệch ma trận tương quan."},{"q":"16. Trong công thức tính cỡ mẫu ước lượng tỷ lệ cắt ngang, trị số $Z_{1-\\\\alpha/2}$ tương ứng với độ tin cậy 95% có giá trị quy định là bao nhiêu?","a":["A. 1.65","B. 1.96","C. 2.58","D. 0.05"],"correct":1,"explain":"Với mức ý nghĩa $\\\\alpha = 0.05$ (độ tin cậy 95%), giá trị phân vị chuẩn Z tương ứng là 1.96."},{"q":"17. Thuật ngữ \u0027PICO\u0027 được sử dụng để xây dựng nội dung nào trong nghiên cứu y học?","a":["A. Khung câu hỏi nghiên cứu lâm sàng.","B. Hệ thống mã hóa SPSS.","C. Thiết kế bảng Pivot Table.","D. Biểu đồ râu hộp."],"correct":0,"explain":"PICO (Patient/Population, Intervention, Comparison, Outcome) là khung chuẩn thiết kế câu hỏi nghiên cứu."},{"q":"18. Sự khác biệt cốt lõi nhất giữa chọn mẫu chùm (Cluster) và chọn mẫu phân tầng (Stratified) là gì?","a":["A. Chọn mẫu phân tầng không dùng tính ngẫu nhiên.","B. Phân tầng là lấy ngẫu nhiên từ TẤT CẢ các tầng; còn Chọn mẫu chùm là chỉ lấy ngẫu nhiên một số chùm và khảo sát toàn bộ chùm đó.","C. Hai phương pháp hoàn toàn trùng khớp nhau.","D. Chọn mẫu chùm chỉ dùng trong nghiên cứu hồi cứu."],"correct":1,"explain":"Phân tầng bảo đảm tầng nào cũng có đại diện tham gia, còn chọn chùm chọn ngẫu nhiên đơn vị chùm làm đại diện."},{"q":"19. Phát biểu nào đúng khi viết phần \u0027Phương pháp nghiên cứu\u0027 trong luận văn CK1?","a":["A. Không cần viết cách chọn mẫu nếu cỡ mẫu lấy thuận tiện.","B. Luôn luôn phải trình bày rõ cách tính cỡ mẫu và phương pháp chọn mẫu cụ thể để hội đồng đánh giá tính đại diện.","C. Chỉ cần copy lý thuyết sách giáo khoa vào luận văn.","D. Chỉ viết về phần chạy mô hình SPSS, bỏ qua phần chọn mẫu."],"correct":1,"explain":"Minh bạch phương pháp luận, cỡ mẫu và quy trình thu thập dữ liệu là yêu cầu bắt buộc của mọi nghiên cứu khoa học."},{"q":"20. SPSS chỉ là công cụ tính toán. Chất lượng và tính đúng đắn của đề tài nghiên cứu y dược được quyết định trước hết bởi yếu tố nào?","a":["A. Việc máy tính chạy nhanh hay chậm.","B. Tư duy phương pháp luận, cách thiết kế biến và chất lượng thu thập mẫu.","C. Sự phức tạp của mô hình hồi quy tuyến tính.","D. Số lượng trang in của cuốn luận văn."],"correct":1,"explain":"Tư duy nghiên cứu khoa học khách quan và kỹ năng thiết lập số liệu là cốt lõi tạo nên giá trị y học thực tiễn."}]};
